class MainActivity : ComponentActivity(), SpellCheckerSession.SpellCheckerSessionListener,
    com.fran.teclas.keyboard.KeyboardHost {

    // ── KeyboardHost (shared-core seam) — wraps the launcher's in-memory query/composeText ──
    private fun hostKind() = openPane?.kind
    private fun hostText(): String = when (hostKind()) {
        PaneKind.CHAT -> composeText
        PaneKind.AI -> aiDraftText
        else -> query
    }
    private fun setHostText(v: String) {
        when (hostKind()) {
            PaneKind.CHAT -> composeText = v
            PaneKind.AI -> {
                aiDraftText = v
                aiDraftActive = true
            }
            else -> query = v
        }
    }
    override fun commitText(text: String) {
        val cur = hostText(); val pos = cursorPos ?: cur.length
        setHostText(cur.substring(0, pos) + text + cur.substring(pos))
        if (cursorPos != null) cursorPos = pos + text.length
    }
    override fun deleteBeforeCursor(count: Int) {
        val cur = hostText(); val pos = cursorPos ?: cur.length
        val start = (pos - count).coerceAtLeast(0)
        setHostText(cur.substring(0, start) + cur.substring(pos))
        if (cursorPos != null) cursorPos = start
    }
    override fun textBeforeCursor(count: Int): String {
        val cur = hostText(); val pos = cursorPos ?: cur.length
        return cur.substring((pos - count).coerceAtLeast(0), pos)
    }
    override fun textAfterCursor(count: Int): String {
        val cur = hostText(); val pos = cursorPos ?: cur.length
        return cur.substring(pos, (pos + count).coerceAtMost(cur.length))
    }
    override fun moveCursor(right: Boolean) {
        val cur = hostText(); val pos = cursorPos ?: cur.length
        val np = (pos + if (right) 1 else -1).coerceIn(0, cur.length)
        cursorPos = if (np == cur.length) null else np
    }

    /** Step the launcher's in-field cursor and repaint the caret (two-finger trackpad panning). */
    private fun moveLauncherCursor(right: Boolean) {
        moveCursor(right)
        renderRibbon()
    }
    override fun editorPackage(): String? = null          // launcher edits its own field
    override fun isPasswordField(): Boolean = false
    override val hostHapticsEnabled: Boolean get() = hapticsEnabled
    override fun onAgenticCommand(text: String) { executeTypeToDoCommand(text) }
    override fun openHostKeyboardSettings() { openTeclasSettingsFromKeyboard() }

    private fun openTeclasSettingsFromKeyboard() {
        keyboardSettingsOpen = false
        query = ""
        libraryOpen = false
        openHere(teclasSettingsTarget())
    }

    // Unified keyboard algorithm — same composite scorer as the IME, reading the same shared
    // "teclas" prefs, so both keyboards rank and learn identically (personal usage, rejected
    // corrections, adapted weights all shared).
    private val personalFreq by lazy { com.fran.teclas.keyboard.unified.PersonalFrequencyStore(prefs()) }
    private val rejectedStore by lazy { com.fran.teclas.keyboard.unified.RejectedCorrectionsStore(prefs()) }
    private val adaptiveWeights by lazy { com.fran.teclas.keyboard.unified.AdaptiveWeights(prefs()) }
    private val contextModel = com.fran.teclas.keyboard.unified.ContextModel()
    private val unifiedRanker by lazy {
        com.fran.teclas.keyboard.unified.UnifiedRanker(
            engine = { predictionEngine },
            personalBoost = { personalFreq.boost(it) },
            isRejectedPair = { t, c -> rejectedStore.contains(t, c) },
            lmProb = { prev, w -> contextModel.prob(prev, w) },
            weights = { adaptiveWeights.weights() }
        )
    }
    // Lazy bigram-LM load, off-main, no-op once loaded — cold start pays nothing.
    private fun warmContextModel() {
        if (contextModel.isLoaded) return
        runCatching { launcherPredictExecutor.execute {
            runCatching { assets.open("dict/en_bigrams.txt").use { contextModel.load(it) } }
        } }
    }
    private val autocorrectCore by lazy {
        com.fran.teclas.keyboard.AutocorrectCore(
            host = this,
            engine = { predictionEngine },
            contextNextWords = { ngramRepo.cachedNextWords(it) },
            useFallback = true,
            ranker = { unifiedRanker },
            rejectedPersist = { t, c -> rejectedStore.add(t, c) },
            rejectedContains = { t, c -> rejectedStore.contains(t, c) },
            isProtectedWord = { w -> isSearchVocabulary(w) }
        )
    }

    /**
     * Tokens the search pipeline treats as meaningful, so autocorrect must leave them alone:
     * currency codes, coin symbols, tickers, and installed app names. These are exactly the words
     * a dictionary "fixes" into something else ("usd"→"use", "aapl"→"Wall"), which silently broke
     * the very searches they were typed for.
     */
    internal fun isSearchVocabulary(word: String): Boolean {
        val w = word.trim().lowercase(Locale.US)
        if (w.length < 2) return false
        if (w in CurrencyApi.TERMS || w in CryptoApi.TERMS) return true
        if (w in BraveSearchApi.STOCK_TERMS) return true
        // Deliberately capitalized short token reads as a ticker ("AAPL", "TSLA").
        if (looksLikeTicker(word)) return true
        // Never rewrite an app the user could be launching ("Zara" → "Zara", not "Zaha").
        if (apps.any { it.label.equals(w, ignoreCase = true) || it.shortName.equals(w, ignoreCase = true) }) return true
        return false
    }
    private val predictionCore by lazy {
        com.fran.teclas.keyboard.PredictionCore(
            this, { predictionEngine }, ngramRepo, ranker = { unifiedRanker },
            languageNextWords = { prev -> contextModel.topContinuations(prev, 3) }
        )
    }
    private val glideCore by lazy { com.fran.teclas.keyboard.GlideCore(this, ngramRepo) }

    private val collator = Collator.getInstance()
    // Bumped whenever anything universalSearchResults() reads changes: the query itself, an async
    // source landing, or a setting applied from a result row. It's the memo's invalidation key —
    // see universalSearchResults / invalidateSearchResults.
    //
    // @Volatile because some writers (predictContext) run off-main and the memo is read on main.
    // Racing increments can lose a count, which is harmless here: the memo only needs the value to
    // DIFFER from the key it cached under, and this only ever moves forward.
    @Volatile private var searchGeneration = 0
    internal var query = ""
        set(value) {
            if (field == value) return
            field = value
            searchGeneration++
        }
    // universalSearchResults() scores every result out of this list, so a package install/uninstall
    // landing mid-query must invalidate the memo — otherwise search keeps serving the old app set.
    internal var apps: List<AppEntry> = emptyList()
        set(value) {
            field = value
            searchGeneration++
        }
