        val device = listOf(Build.MANUFACTURER, Build.BRAND, Build.DEVICE, Build.MODEL)
            .joinToString(" ")
            .lowercase(Locale.US)
        return device.contains("vivo") || device.contains("iqoo")
    }

    private fun isHonorDevice(): Boolean {
        val device = listOf(Build.MANUFACTURER, Build.BRAND, Build.DEVICE, Build.MODEL)
            .joinToString(" ")
