    }

    private inner class ZeissCameraButtonView(context: Context) : TextView(context) {
        private val shutterPaint = Paint(Paint.ANTI_ALIAS_FLAG)
        private var shutterProgress = 0f
        private var shutterAnimator: ValueAnimator? = null

        fun setShutterClosed(closed: Boolean) {
            shutterAnimator?.cancel()
            shutterProgress = if (closed) 1f else 0f
            invalidate()
        }

        fun animateShutterClosed() = animateShutterTo(1f, 820L)

        fun animateShutterOpen() = animateShutterTo(0f, 980L)

        private fun animateShutterTo(target: Float, durationMs: Long) {
            shutterAnimator?.cancel()
            shutterAnimator = ValueAnimator.ofFloat(shutterProgress, target).apply {
                duration = durationMs
                interpolator = DecelerateInterpolator()
                addUpdateListener {
                    shutterProgress = it.animatedValue as Float
                    invalidate()
                }
                start()
            }
        }

        override fun onDraw(canvas: Canvas) {
            val originalTextAlpha = paint.alpha
            if (shutterProgress > 0.01f) {
                paint.alpha = (255 * (1f - shutterProgress * 0.92f)).toInt().coerceIn(0, 255)
            }
            super.onDraw(canvas)
            paint.alpha = originalTextAlpha
            if (shutterProgress <= 0.01f) return
            val cx = width / 2f
            val cy = height / 2f
            val radius = minOf(width, height).toFloat() * 0.56f
            val outer = maxOf(width, height).toFloat() * 1.35f
            val bladeCount = 6
            val segment = Math.PI.toFloat() * 2f / bladeCount
            val aperture = (radius * 0.78f * (1f - shutterProgress)).coerceAtLeast(if (shutterProgress > 0.96f) 0f else dp(1).toFloat())
            val twist = shutterProgress * segment * 0.92f

            val clip = Path().apply {
                addRoundRect(0f, 0f, width.toFloat(), height.toFloat(), dp(9).toFloat(), dp(9).toFloat(), Path.Direction.CW)
            }
            canvas.save()
            canvas.clipPath(clip)

            shutterPaint.style = Paint.Style.FILL
            shutterPaint.shader = android.graphics.RadialGradient(
                cx,
                cy,
                outer,
                intArrayOf(0xFF141A28.toInt(), 0xFF05070D.toInt(), 0xFF000000.toInt()),
                floatArrayOf(0f, 0.55f, 1f),
                Shader.TileMode.CLAMP
            )
            canvas.drawRoundRect(0f, 0f, width.toFloat(), height.toFloat(), dp(9).toFloat(), dp(9).toFloat(), shutterPaint)
            shutterPaint.shader = null

            shutterPaint.shader = android.graphics.RadialGradient(
                cx,
                cy,
                radius * 1.18f,
                intArrayOf(
                    Color.argb((16 + shutterProgress * 24).toInt(), 170, 198, 255),
                    Color.argb((160 + shutterProgress * 70).toInt(), 0, 0, 0)
                ),
                floatArrayOf(0f, 1f),
                Shader.TileMode.CLAMP
            )
            canvas.drawRoundRect(0f, 0f, width.toFloat(), height.toFloat(), dp(9).toFloat(), dp(9).toFloat(), shutterPaint)
            shutterPaint.shader = null

            repeat(bladeCount) { index ->
                val start = -Math.PI.toFloat() / 2f + index * segment + twist
                val end = start + segment * 1.35f
                val innerStart = start - segment * 0.28f
                val innerEnd = end - segment * 0.28f
                val p1x = cx + kotlin.math.cos(start) * outer
                val p1y = cy + kotlin.math.sin(start) * outer
                val p2x = cx + kotlin.math.cos(end) * outer
                val p2y = cy + kotlin.math.sin(end) * outer
                val p3x = cx + kotlin.math.cos(innerEnd) * aperture
                val p3y = cy + kotlin.math.sin(innerEnd) * aperture
                val p4x = cx + kotlin.math.cos(innerStart) * aperture
                val p4y = cy + kotlin.math.sin(innerStart) * aperture
                val blade = Path().apply {
                    moveTo(p1x, p1y)
                    lineTo(p2x, p2y)
                    lineTo(p3x, p3y)
                    lineTo(p4x, p4y)
                    close()
                }
                shutterPaint.style = Paint.Style.FILL
                shutterPaint.color = if (index % 2 == 0) 0xFF05070D.toInt() else 0xFF111724.toInt()
                canvas.drawPath(blade, shutterPaint)
                shutterPaint.style = Paint.Style.STROKE
                shutterPaint.strokeWidth = dp(1).toFloat()
                shutterPaint.color = Color.argb(145, 94, 116, 154)
                canvas.drawPath(blade, shutterPaint)
            }

            canvas.restore()

            shutterPaint.style = Paint.Style.STROKE
            shutterPaint.strokeWidth = dp(2).toFloat()
            shutterPaint.color = Color.argb(190, 0, 0, 0)
            canvas.drawCircle(cx, cy, radius, shutterPaint)

            shutterPaint.strokeWidth = dp(1).toFloat()
            shutterPaint.color = Color.argb(92, 180, 205, 255)
            canvas.drawCircle(cx, cy, radius - dp(2), shutterPaint)

            shutterPaint.style = Paint.Style.FILL
            shutterPaint.color = Color.argb(235, 0, 0, 0)
            canvas.drawCircle(cx, cy, aperture.coerceAtLeast(dp(1).toFloat()), shutterPaint)
            if (shutterProgress > 0.72f) {
                shutterPaint.style = Paint.Style.STROKE
                shutterPaint.strokeWidth = dp(1).toFloat()
                shutterPaint.color = Color.argb((180 * shutterProgress).toInt(), 150, 170, 210)
                repeat(bladeCount) { index ->
                    val angle = -Math.PI.toFloat() / 2f + index * segment + twist - segment * 0.22f
                    canvas.drawLine(
                        cx,
                        cy,
                        cx + kotlin.math.cos(angle) * radius * 0.92f,
                        cy + kotlin.math.sin(angle) * radius * 0.92f,
                        shutterPaint
                    )
                }
            }
        }
    }

    private fun photoStampLabel(): String {
        if (isVivoDevice()) return "ZEISS"
        val maker = Build.MANUFACTURER.ifBlank { Build.BRAND }.ifBlank { "ANDROID" }
        return maker.uppercase(Locale.US)
    }

    private fun openVivoCamera() {
        val intents = listOf(
            Intent(Intent.ACTION_MAIN).addCategory("android.intent.category.APP_CAMERA"),
            Intent(android.provider.MediaStore.INTENT_ACTION_STILL_IMAGE_CAMERA),
            Intent(android.provider.MediaStore.ACTION_IMAGE_CAPTURE)
        )
        intents.firstOrNull { it.resolveActivity(packageManager) != null }?.let {
            startSafeIntent(it, "Camera isn't available here")
            return
        }
        listOf("com.android.camera", "com.vivo.camera", "com.bbk.camera").forEach { pkg ->
            packageManager.getLaunchIntentForPackage(pkg)?.let {
                startSafeIntent(it, "Camera isn't available here")
                return
            }
        }
        Toast.makeText(this, "Camera isn't available here", Toast.LENGTH_SHORT).show()
    }

    // ---- Docked vs widget: independent phone home setups (wallpaper + weather widget) ----
    // Docked mode ("half and half") and widget mode ("full screen") keep separate wallpaper and
    // weather-widget prefs, so arranging one never disturbs the other. On a phone the docked
    // namespace suffixes the shared key; widget mode and the unfolded inner display use the base key.
    // ensureDockedHomeSeed() copies the current shared values into the docked namespace once, so both
    // modes start identical and only diverge as each is edited.
    private fun phoneDockedHomeScope(): Boolean =
        !isUnfoldedInnerLayoutActive() && keyboardPlacement == KEYBOARD_PLACEMENT_DOCKED

    internal fun homeScopedKey(base: String): String =
        if (phoneDockedHomeScope()) base + DOCKED_HOME_SUFFIX else base

    private fun ensureDockedHomeSeed() {
        val p = prefs()
        if (p.getBoolean(DOCKED_HOME_SEEDED_PREF, false)) return
        val e = p.edit()
        listOf(HOME_COVER_WALLPAPER_URI_PREF, WEATHER_WIDGET_STYLE_PREF).forEach {
            if (p.contains(it)) e.putString(it + DOCKED_HOME_SUFFIX, p.getString(it, null))
        }
        listOf(HOME_COVER_WALLPAPER_ZOOM_PREF, HOME_COVER_WALLPAPER_OFFSET_X_PREF,
            HOME_COVER_WALLPAPER_OFFSET_Y_PREF, WEATHER_WIDGET_POS_X_PREF, WEATHER_WIDGET_POS_Y_PREF).forEach {
            if (p.contains(it)) e.putInt(it + DOCKED_HOME_SUFFIX, p.getInt(it, 0))
        }
        listOf(HOME_SYSTEM_WALLPAPER_PREF, HOME_LOCK_WALLPAPER_PREF).forEach {
            if (p.contains(it)) e.putBoolean(it + DOCKED_HOME_SUFFIX, p.getBoolean(it, false))
        }
        e.putBoolean(DOCKED_HOME_SEEDED_PREF, true).apply()
    }

    private fun useLockscreenWallpaperOnHome(): Boolean =
        prefs().getBoolean(homeScopedKey(HOME_LOCK_WALLPAPER_PREF), false)

    private fun useSystemWallpaperOnHome(): Boolean =
        prefs().getBoolean(homeScopedKey(HOME_SYSTEM_WALLPAPER_PREF), true)

    private fun innerHomeWallpaperUri(): Uri? =
        prefs().getString(HOME_INNER_WALLPAPER_URI_PREF, null)
            ?.takeIf { it.isNotBlank() }
            ?.let { runCatching { Uri.parse(it) }.getOrNull() }

    private fun coverHomeWallpaperUri(): Uri? =
        prefs().getString(homeScopedKey(HOME_COVER_WALLPAPER_URI_PREF), null)
            ?.takeIf { it.isNotBlank() }
            ?.let { runCatching { Uri.parse(it) }.getOrNull() }

    private fun activeHomeWallpaperUri(): Uri? {
        if (useSystemWallpaperOnHome()) return null
        if (isUnfoldedInnerLayoutActive()) {
            // Inner and cover wallpapers stay independently configurable. If the inner screen has
            // never been assigned one, fall back to the cover wallpaper instead of showing a black
            // canvas after a picker/config activity rebuilds the unfolded home.
            return innerHomeWallpaperUri() ?: coverHomeWallpaperUri()
        } else {
            return coverHomeWallpaperUri() ?: innerHomeWallpaperUri()
        }
    }

    private fun activeWallpaperUriPref(inner: Boolean = isUnfoldedInnerLayoutActive()): String =
        if (inner) HOME_INNER_WALLPAPER_URI_PREF else homeScopedKey(HOME_COVER_WALLPAPER_URI_PREF)

    private fun activeWallpaperZoomPref(): String =
        if (isUnfoldedInnerLayoutActive()) HOME_INNER_WALLPAPER_ZOOM_PREF else homeScopedKey(HOME_COVER_WALLPAPER_ZOOM_PREF)

    private fun activeWallpaperOffsetXPref(): String =
        if (isUnfoldedInnerLayoutActive()) HOME_INNER_WALLPAPER_OFFSET_X_PREF else homeScopedKey(HOME_COVER_WALLPAPER_OFFSET_X_PREF)

    private fun activeWallpaperOffsetYPref(): String =
        if (isUnfoldedInnerLayoutActive()) HOME_INNER_WALLPAPER_OFFSET_Y_PREF else homeScopedKey(HOME_COVER_WALLPAPER_OFFSET_Y_PREF)

    private fun innerWallpaperZoom(): Float =
        prefs().getInt(activeWallpaperZoomPref(), 100).coerceIn(100, 260) / 100f

    private fun innerWallpaperOffsetX(): Float =
        prefs().getInt(activeWallpaperOffsetXPref(), 0).coerceIn(-100, 100) / 100f

    private fun innerWallpaperOffsetY(): Float =
        prefs().getInt(activeWallpaperOffsetYPref(), 0).coerceIn(-100, 100) / 100f

    private fun innerWallpaperModeActive(): Boolean =
        openPane == null && (useSystemWallpaperOnHome() || activeHomeWallpaperUri() != null)

    private fun launcherWallpaperCanvasActive(): Boolean = true

    private fun widgetModeNativeGlassActive(): Boolean =
        isUnfoldedInnerLayoutActive() || keyboardPlacement == KEYBOARD_PLACEMENT_WIDGET

    internal fun nativeGlassSurfaceActive(): Boolean =
        isHonorDevice() || widgetModeNativeGlassActive()

    private fun normalizeInnerWallpaperTransform() {
        val zoomPref = activeWallpaperZoomPref()
        val zoom = prefs().getInt(zoomPref, 100)
        if (zoom < 100) {
            prefs().edit().putInt(zoomPref, 100).apply()
        }
    }

    private fun glassEffectsEnabled(): Boolean =
        prefs().getBoolean(GLASS_EFFECTS_PREF, true)

    // The App Library uses the dark neu design (opaque neumorphic panels), never the glass sheet —
    // so it reads as a solid, consistent surface regardless of the global glass-effects setting.
    private fun appLibraryGlassEnabled(): Boolean = false

    internal fun focusSurfaceGlassEnabled(): Boolean =
        isHonorDevice() || glassEffectsEnabled() || widgetModeNativeGlassActive() || innerWallpaperModeActive()

    private fun gridWorkspaceLabEnabled(): Boolean =
        prefs().getBoolean(GRID_WORKSPACE_LAB_PREF, false)

    private fun cardsViewEnabled(): Boolean =
        prefs().getBoolean(CARDS_VIEW_ENABLED_PREF, false)

    private fun gridHomeAliasComponent() =
        ComponentName(this, "com.fran.teclas.grid.GridHomeAlias")

    private fun gridHomeAliasEnabled(): Boolean =
        packageManager.getComponentEnabledSetting(gridHomeAliasComponent()) ==
            android.content.pm.PackageManager.COMPONENT_ENABLED_STATE_ENABLED

    private fun setGridHomeAliasEnabled(enabled: Boolean) {
        packageManager.setComponentEnabledSetting(
            gridHomeAliasComponent(),
            if (enabled) android.content.pm.PackageManager.COMPONENT_ENABLED_STATE_ENABLED
            else android.content.pm.PackageManager.COMPONENT_ENABLED_STATE_DISABLED,
            android.content.pm.PackageManager.DONT_KILL_APP,
        )
    }

    private fun appLibraryDefaultHome(): Boolean =
        prefs().getBoolean(APP_LIBRARY_DEFAULT_HOME_PREF, false)

    internal fun isUnfoldedInnerLayoutActive(): Boolean =
        (foldPosture is FoldPosture.Inner || foldPosture is FoldPosture.HalfOpen) &&
            resources.configuration.screenWidthDp >= 600

    /** Lower-panel height (px) in tabletop Flex Mode (half-open, horizontal hinge), else 0.
     *  Galaxy Folds report HALF_OPENED through most of the fold arc, so without this the
     *  inner screen would drop back to the stretched cover layout the moment the hinge bends.
     *  Content keeps to the upright upper panel; the bottom-anchored keyboard overlay stays
     *  on the flat lower half — the Flex Mode typing split. */
    private fun tabletopLowerPanelInset(): Int {
        val posture = foldPosture as? FoldPosture.HalfOpen ?: return 0
        if (posture.vertical) return 0
        val screenHeight = resources.displayMetrics.heightPixels
        // The root keyboard dock already owns the bottom of the screen (it's a sibling below
        // the content frame), so only pad the content for the slice of the lower panel the
        // dock doesn't cover.
        val dockReserved = activeRootDockHeight() + launcherDockedKeyboardBottomLift() + keyboardBottomLift()
        return (screenHeight - posture.hinge.top - dockReserved).coerceIn(0, screenHeight / 2)
    }

    private fun innerKeyboardWidthPercent(): Int =
        prefs().getInt(INNER_KEYBOARD_WIDTH_PREF, 68).coerceIn(48, 100)

    private fun unfoldedFocusHorizontalInset(): Int = dp(30)

    private fun unfoldedKeyboardPanelWidth(): Int {
        val maxWidth = resources.displayMetrics.widthPixels
        if (isUnfoldedInnerLayoutActive() && !innerKeyboardEditMode) {
            return (maxWidth - unfoldedFocusHorizontalInset() * 2).coerceAtLeast(dp(720))
        }
        val minWidth = dp(720)
        val upperBound = (maxWidth - dp(36)).coerceAtLeast(minWidth)
        return (maxWidth * innerKeyboardWidthPercent() / 100f).toInt().coerceIn(minWidth, upperBound)
    }

    private fun unfoldedKeyboardPanelSnapLimit(panelWidth: Int = unfoldedKeyboardPanelWidth()): Int =
        ((resources.displayMetrics.widthPixels - panelWidth) / 2).coerceAtLeast(0)

    private fun unfoldedKeyboardPanelOffsetX(panelWidth: Int = unfoldedKeyboardPanelWidth()): Int =
        if (isUnfoldedInnerLayoutActive() && !innerKeyboardEditMode) 0
        else innerKeyboardOffsetX().coerceIn(-unfoldedKeyboardPanelSnapLimit(panelWidth), unfoldedKeyboardPanelSnapLimit(panelWidth))

    private fun unfoldedKeyboardPanelLeft(panelWidth: Int = unfoldedKeyboardPanelWidth()): Int {
        val screenWidth = resources.displayMetrics.widthPixels
        val base = ((screenWidth - panelWidth) / 2).coerceAtLeast(0)
        return (base + unfoldedKeyboardPanelOffsetX(panelWidth)).coerceIn(0, (screenWidth - panelWidth).coerceAtLeast(0))
    }

    private fun unfoldedKeyboardPanelParams(panelWidth: Int = unfoldedKeyboardPanelWidth()): FrameLayout.LayoutParams =
        FrameLayout.LayoutParams(panelWidth, FrameLayout.LayoutParams.MATCH_PARENT, Gravity.BOTTOM or Gravity.LEFT).apply {
            leftMargin = unfoldedKeyboardPanelLeft(panelWidth)
        }

    private fun forceFoldableWidgetPlacement() {
        if (!isUnfoldedInnerLayoutActive() || keyboardPlacement == KEYBOARD_PLACEMENT_WIDGET) return
        foldPreviousKeyboardPlacement = foldPreviousKeyboardPlacement ?: keyboardPlacement
        keyboardPlacement = KEYBOARD_PLACEMENT_WIDGET
        VivoDockedExperiment.clearViewportTruncation(this)
        stopService(Intent(this, DockedKeyboardService::class.java))
    }

    private fun innerKeyboardSizeBoost(): Int =
        (innerKeyboardPreviewBoost ?: prefs().getInt(INNER_KEYBOARD_SIZE_BOOST_PREF, 52)).coerceIn(-20, 150)

    private fun innerKeyboardOffsetX(): Int =
        prefs().getInt(INNER_KEYBOARD_OFFSET_X_PREF, 0)

    private fun innerKeyboardOffsetY(): Int =
        prefs().getInt(INNER_KEYBOARD_OFFSET_Y_PREF, 0)

    private fun effectiveKeyboardSize(): Int =
        (keyboardSize + if (isUnfoldedInnerLayoutActive()) innerKeyboardSizeBoost() + 12 else 0)
            .coerceIn(0, if (isUnfoldedInnerLayoutActive()) 190 else 100)

    private fun handleFoldPosture(posture: FoldPosture) {
        val wasInner = isUnfoldedInnerLayoutActive()
        val wasTabletopInset = tabletopLowerPanelInset()
        saveWidgetKeyboardHiddenForCurrentPosture()
        foldPosture = posture
        val isInner = isUnfoldedInnerLayoutActive()
        val tabletopInset = tabletopLowerPanelInset()
        homeWallpaperDrawable = null
        innerWallpaperImageView = null
        widgetKeyboardHidden = loadWidgetKeyboardHiddenForCurrentPosture()
        widgetKeyboardSliderAnimating = false
        if (!wasInner && isInner) {
            forceFoldableWidgetPlacement()
            applyUnfoldedContextSwitch()
        } else if (wasInner && !isInner) {
            restoreFoldedContextIfNeeded()
            restoreFoldedKeyboardPlacementIfNeeded()
        }
        if (wasInner != isInner && ::rootView.isInitialized) {
            libraryOpen = if (isInner) false else appLibraryDefaultHome()
            openPane = if (isInner) null else openPane
            keyboardSettingsOpen = false
            render()
        } else if (isInner && tabletopInset != wasTabletopInset && ::rootView.isInitialized) {
            // Tabletop Flex Mode engaged/released (or the hinge line moved): rebuild so the
            // content's bottom inset tracks the hinge.
            render()
        } else if (isInner) {
            refreshUnfoldedLibraryContent()
            refreshUnfoldedFocusContent()
            renderFavoritesDock()
        }
    }

    private fun applyUnfoldedContextSwitch() {
        val target = SpaceManager.space(this, "work")
            ?: SpaceManager.spaces(this).firstOrNull { it.enabled && it.id == "home" }
            ?: SpaceManager.spaces(this).firstOrNull { it.enabled }
            ?: return
        foldPreviousSpaceLock = SpaceManager.lockedSpaceId(this)
        foldAutoLockActive = true
        foldBannerSpace = null
        SpaceManager.lock(this, target.id)
        invalidateLibraryCaches()
        refreshPredictContext(rerender = true)
    }

    private fun restoreFoldedContextIfNeeded() {
        if (!foldAutoLockActive) return
        SpaceManager.lock(this, foldPreviousSpaceLock)
        foldPreviousSpaceLock = null
        foldAutoLockActive = false
        foldBannerSpace = null
        invalidateLibraryCaches()
        refreshPredictContext(rerender = true)
    }

    private fun restoreFoldedKeyboardPlacementIfNeeded() {
        val previous = foldPreviousKeyboardPlacement ?: return
        foldPreviousKeyboardPlacement = null
        keyboardPlacement = previous
        if (previous == KEYBOARD_PLACEMENT_DOCKED) syncVivoDockedExperiment()
    }

    /** Decode a wallpaper source at screen-fill size instead of full camera resolution. A 4-12 MP
     *  image decoded as-is becomes a texture several times larger than the display — pure GPU heat.
     *  [open] must return a fresh stream on each call (bounds pass + pixel pass). */
    private fun decodeWallpaperSampled(open: () -> java.io.InputStream?): android.graphics.Bitmap? {
        val bounds = BitmapFactory.Options().apply { inJustDecodeBounds = true }
        // Bounds-only pass: decodeStream returns null here by design, it only fills outWidth/Height.
        (open() ?: return null).use { BitmapFactory.decodeStream(it, null, bounds) }
        if (bounds.outWidth <= 0 || bounds.outHeight <= 0) return null
        val dm = resources.displayMetrics
        // Size for the current zoom (plus a little slack); the zoom slider nulls
        // homeWallpaperDrawable on change, so a new zoom always re-decodes.
        val zoom = innerWallpaperZoom()
        val target = (maxOf(dm.widthPixels, dm.heightPixels) * zoom * 1.15f).toInt().coerceAtLeast(1)
        var sample = 1
        while (maxOf(bounds.outWidth, bounds.outHeight) / (sample * 2) >= target) sample *= 2
        val opts = BitmapFactory.Options().apply { inSampleSize = sample }
        return open()?.use { BitmapFactory.decodeStream(it, null, opts) }
    }

    /** Cheap identity of the current wallpaper sources, so resume can skip the decode + render
     *  when nothing changed. Wallpaper ids bump whenever the device wallpaper is replaced. */
    private fun deviceWallpaperSignature(): String {
        val uri = activeHomeWallpaperUri()?.toString().orEmpty()
        val themeWallpaper = prefs().getString(ThemeRepository.THEME_WALLPAPER_ID_PREF, WallpaperRegistry.SYSTEM_WALLPAPER_ID).orEmpty()
        val dynamicPhase = if (themeWallpaper == WallpaperRegistry.FLUID_HOURS_ID) FluidHours.currentPhase().name else ""
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.N) return "$uri|legacy"
        val manager = WallpaperManager.getInstance(this)
        val sys = runCatching { manager.getWallpaperId(WallpaperManager.FLAG_SYSTEM) }.getOrDefault(-1)
        val lock = runCatching { manager.getWallpaperId(WallpaperManager.FLAG_LOCK) }.getOrDefault(-1)
        return "$uri|$themeWallpaper|$dynamicPhase|$sys|$lock|${useSystemWallpaperOnHome()}|${useLockscreenWallpaperOnHome()}"
    }

    private fun fluidHoursWallpaperActive(): Boolean =
        !useSystemWallpaperOnHome() &&
            activeHomeWallpaperUri() == null &&
            prefs().getString(ThemeRepository.THEME_WALLPAPER_ID_PREF, WallpaperRegistry.SYSTEM_WALLPAPER_ID) == WallpaperRegistry.FLUID_HOURS_ID

    private fun scheduleFluidHoursWallpaperRefresh() {
        fluidHoursRefreshRunnable?.let { handler.removeCallbacks(it) }
        if (!fluidHoursWallpaperActive()) {
            fluidHoursRefreshRunnable = null
            return
        }
        val runnable = Runnable {
            if (fluidHoursWallpaperActive()) {
                homeWallpaperDrawable = null
                refreshHomeWallpaperAsync()
                scheduleFluidHoursWallpaperRefresh()
            }
        }
        fluidHoursRefreshRunnable = runnable
        handler.postDelayed(runnable, FluidHours.nextBoundaryDelayMillis().coerceAtMost(15 * 60_000L))
    }

    private fun loadHomeWallpaperDrawable(): Drawable? {
        normalizeInnerWallpaperTransform()
        val sourceSig = deviceWallpaperSignature()
        if (homeWallpaperUnavailableSig == sourceSig) return null
        val selectedDrawable = activeHomeWallpaperUri()?.let { uri ->
            runCatching {
                decodeWallpaperSampled { contentResolver.openInputStream(uri) }
                    ?.let { bitmap -> BitmapDrawable(resources, bitmap) }
            }.onFailure {
                android.util.Log.w("TeclasWallpaper", "Selected wallpaper load failed", it)
            }.getOrNull()
        }
        if (selectedDrawable != null) {
            homeWallpaperUnavailableSig = null
            deviceWallpaperFileDeniedSig = null
            return selectedDrawable
        }
        if (!useSystemWallpaperOnHome()) {
            val themedWallpaper = prefs().getString(ThemeRepository.THEME_WALLPAPER_ID_PREF, WallpaperRegistry.SYSTEM_WALLPAPER_ID)
                ?: WallpaperRegistry.SYSTEM_WALLPAPER_ID
            if (themedWallpaper != WallpaperRegistry.SYSTEM_WALLPAPER_ID) {
                WallpaperRegistry(this).loadDrawable(themedWallpaper)?.let { return it }
            }
        }
        if (!launcherWallpaperCanvasActive() && !useLockscreenWallpaperOnHome()) return null
        val manager = WallpaperManager.getInstance(this)
        fun fileDrawable(which: Int): Drawable? {
            if (Build.VERSION.SDK_INT < Build.VERSION_CODES.N) return null
            if (deviceWallpaperFileDeniedSig == sourceSig) return null
            return runCatching {
                decodeWallpaperSampled {
                    manager.getWallpaperFile(which)
                        ?.let { android.os.ParcelFileDescriptor.AutoCloseInputStream(it) }
                }?.let { bitmap -> BitmapDrawable(resources, bitmap) }
            }.onFailure {
                if (it is SecurityException) {
                    deviceWallpaperFileDeniedSig = sourceSig
                    android.util.Log.w("TeclasWallpaper", "Device wallpaper file access denied; using live drawable fallback")
                } else {
                    android.util.Log.w("TeclasWallpaper", "Device wallpaper file load failed for $which", it)
                }
            }.getOrNull()
        }
        // Default to the device HOME (system) wallpaper — "whatever the user is using" — and
        // only prefer the lockscreen image when the user turned that toggle on. Live wallpapers
        // have no file/bitmap, so these all return null for them (see the live-wallpaper note).
        val preferLock = useLockscreenWallpaperOnHome()
        val primary = if (preferLock) WallpaperManager.FLAG_LOCK else WallpaperManager.FLAG_SYSTEM
        val secondary = if (preferLock) WallpaperManager.FLAG_SYSTEM else WallpaperManager.FLAG_LOCK
        val drawable = fileDrawable(primary)
            ?: fileDrawable(secondary)
            ?: runCatching { manager.peekDrawable() }.getOrNull()
            ?: runCatching { manager.drawable }.getOrNull()
            ?: runCatching { manager.fastDrawable }.getOrNull()
        android.util.Log.i(
            "TeclasWallpaper",
            "device wallpaper loaded=${drawable != null} type=${drawable?.javaClass?.simpleName}"
        )
        if (drawable == null) homeWallpaperUnavailableSig = sourceSig else homeWallpaperUnavailableSig = null
        return drawable?.constantState?.newDrawable(resources)?.mutate() ?: drawable
    }

    /** True while an async wallpaper decode is in flight, so render passes don't re-kick it. */
    private var homeWallpaperLoading = false

    /** Decode the home wallpaper off the main thread, then apply it and re-render the home
     *  canvas. The synchronous decode cost a StrictMode-measured 1.5 s of main-thread jank on
     *  cold start and on every actual wallpaper change. */
    internal fun refreshHomeWallpaperAsync() {
        val sig = deviceWallpaperSignature()
        homeWallpaperSourceSig = sig
        if (homeWallpaperLoading) return
        homeWallpaperLoading = true
        mediaUiScope.launch(Dispatchers.IO) {
            val loaded = runCatching { loadHomeWallpaperDrawable() }.getOrNull()
            withContext(Dispatchers.Main) {
                homeWallpaperLoading = false
                if (homeWallpaperSourceSig == sig) {
                    if (loaded != null) {
                        homeWallpaperDrawable = loaded
                        lastGoodHomeWallpaperDrawable = loaded.constantState?.newDrawable(resources)?.mutate() ?: loaded
                    } else if (homeWallpaperDrawable == null && lastGoodHomeWallpaperDrawable != null) {
                        homeWallpaperDrawable = lastGoodHomeWallpaperDrawable?.constantState?.newDrawable(resources)?.mutate()
                            ?: lastGoodHomeWallpaperDrawable
                    }
                    if (::rootView.isInitialized && openPane == null) render()
                } else {
                    // Source changed mid-decode: this result is stale — decode the new one.
                    refreshHomeWallpaperAsync()
                }
            }
        }
    }

    private fun homeWallpaperLayer(): View? {
        // Cached-only on the render path: a miss kicks the async decode and this pass renders
        // the base color; the decode completion re-renders with the wallpaper.
        val wallpaper = homeWallpaperDrawable ?: lastGoodHomeWallpaperDrawable
        if (wallpaper == null &&
            launcherWallpaperCanvasActive() &&
            !homeWallpaperLoading &&
            homeWallpaperUnavailableSig != deviceWallpaperSignature()
        ) {
            refreshHomeWallpaperAsync()
        }
        if (wallpaper == null && !launcherWallpaperCanvasActive()) return null
        innerWallpaperImageView = null
        return object : FrameLayout(this) {
            override fun dispatchTouchEvent(ev: MotionEvent): Boolean {
                if (handleUnfoldedWeatherHold(ev)) return true
                if (handleHomeAddLongPress(this, ev)) return true
                return super.dispatchTouchEvent(ev)
            }
        }.apply {
            if (wallpaper != null) {
                addView(ImageView(context).apply {
                    setImageDrawable(wallpaper.constantState?.newDrawable(resources)?.mutate() ?: wallpaper)
                    scaleType = ImageView.ScaleType.MATRIX
                    alpha = 1f
                    innerWallpaperImageView = this
                    post { applyInnerWallpaperMatrix(this) }
                }, FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.MATCH_PARENT)
            } else {
                addView(View(context).apply {
                    background = GradientDrawable(
                        GradientDrawable.Orientation.TL_BR,
                        if (activeNeuTokens.mode == NeuMode.LIGHT) {
                            intArrayOf(0xFFF1F5F7.toInt(), 0xFFE7F0F3.toInt(), 0xFFF4EFE8.toInt())
                        } else {
                            intArrayOf(0xFF111923.toInt(), 0xFF071015.toInt(), 0xFF121016.toInt())
                        }
                    )
                }, FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.MATCH_PARENT)
            }
            if (wallpaper == null) {
                addView(View(context).apply {
                    background = GradientDrawable(
                        GradientDrawable.Orientation.TOP_BOTTOM,
                        if (activeNeuTokens.mode == NeuMode.LIGHT) {
                            intArrayOf(0x10F4F5F1, 0x18EEF0EA, 0x22DADDD8)
                        } else {
                            intArrayOf(0x2206080B, 0x1A12161C, 0x2A050609)
                        }
                    )
                }, FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.MATCH_PARENT)
            }
        }
    }

    // Last matrix applied by applyInnerWallpaperMatrix, so the 30 Hz motion path can skip the
    // full-screen invalidate when the computed transform hasn't visibly changed.
    private var lastWallpaperMatrixImage: java.lang.ref.WeakReference<ImageView>? = null
    private var lastWallpaperMatrixScale = 0f
    private var lastWallpaperMatrixTx = Float.NaN
    private var lastWallpaperMatrixTy = Float.NaN

    private fun applyInnerWallpaperMatrix(image: ImageView) {
        val drawable = image.drawable ?: return
        val viewW = image.width.toFloat()
        val viewH = image.height.toFloat()
        val drawW = drawable.intrinsicWidth.takeIf { it > 0 }?.toFloat() ?: return
        val drawH = drawable.intrinsicHeight.takeIf { it > 0 }?.toFloat() ?: return
        if (viewW <= 0f || viewH <= 0f) return
        val fillScale = maxOf(viewW / drawW, viewH / drawH)
        val baseScale = fillScale * innerWallpaperZoom()
        val scaledW = drawW * baseScale
        val scaledH = drawH * baseScale
        val maxX = ((scaledW - viewW) / 2f).coerceAtLeast(0f)
        val maxY = ((scaledH - viewH) / 2f).coerceAtLeast(0f)
        val offsetX = innerWallpaperOffsetX().coerceIn(-1f, 1f)
        val offsetY = innerWallpaperOffsetY().coerceIn(-1f, 1f)
        val tx = (viewW - scaledW) / 2f + maxX * offsetX
        val ty = (viewH - scaledH) / 2f + maxY * offsetY
        if (lastWallpaperMatrixImage?.get() === image && baseScale == lastWallpaperMatrixScale &&
            abs(tx - lastWallpaperMatrixTx) < 0.4f && abs(ty - lastWallpaperMatrixTy) < 0.4f
        ) return // sub-half-px shift: not visible, not worth re-rasterizing the wallpaper
        lastWallpaperMatrixImage = java.lang.ref.WeakReference(image)
        lastWallpaperMatrixScale = baseScale
        lastWallpaperMatrixTx = tx
        lastWallpaperMatrixTy = ty
        image.imageMatrix = Matrix().apply {
            postScale(baseScale, baseScale)
            postTranslate(tx, ty)
        }
    }

    private fun innerWallpaperPanBounds(image: ImageView, zoom: Float = innerWallpaperZoom()): Pair<Float, Float> {
        val drawable = image.drawable ?: return 0f to 0f
        val viewW = image.width.toFloat()
        val viewH = image.height.toFloat()
        val drawW = drawable.intrinsicWidth.takeIf { it > 0 }?.toFloat() ?: return 0f to 0f
        val drawH = drawable.intrinsicHeight.takeIf { it > 0 }?.toFloat() ?: return 0f to 0f
        if (viewW <= 0f || viewH <= 0f) return 0f to 0f
        val fillScale = maxOf(viewW / drawW, viewH / drawH)
        val baseScale = fillScale * zoom
        return (((drawW * baseScale) - viewW) / 2f).coerceAtLeast(1f) to
            (((drawH * baseScale) - viewH) / 2f).coerceAtLeast(1f)
    }

    private fun setInnerWallpaperTransform(zoomPercent: Int, offsetXPercent: Int, offsetYPercent: Int) {
        prefs().edit()
            .putInt(activeWallpaperZoomPref(), zoomPercent.coerceIn(100, 260))
            .putInt(activeWallpaperOffsetXPref(), offsetXPercent.coerceIn(-100, 100))
            .putInt(activeWallpaperOffsetYPref(), offsetYPercent.coerceIn(-100, 100))
            .apply()
        innerWallpaperImageView?.let { applyInnerWallpaperMatrix(it) }
    }

    internal fun cancelWallpaperLongPress() {
        wallpaperLongPressRunnable?.let { handler.removeCallbacks(it) }
        wallpaperLongPressRunnable = null
        homeAddLongPressRunnable?.let { handler.removeCallbacks(it) }
        homeAddLongPressRunnable = null
        homeAddLongPressFired = false
    }

    private fun installWallpaperEditLongPress(surface: View) {
        // Wallpaper edit stays out of the home long-press path: this gesture now opens the
        // lightweight Add-to-Home sheet, with its own slop/eligibility guard in dispatch.
        cancelWallpaperLongPress()
        surface.isLongClickable = false
        surface.setOnLongClickListener(null)
        surface.setOnTouchListener(null)
    }

    private fun handleHomeAddLongPress(surface: View, event: MotionEvent): Boolean {
        when (event.actionMasked) {
            MotionEvent.ACTION_DOWN -> {
                homeAddLongPressStartX = event.rawX
                homeAddLongPressStartY = event.rawY
                homeAddLongPressFired = false
                homeAddLongPressRunnable?.let { handler.removeCallbacks(it) }
                homeAddLongPressRunnable = null
                if (!canArmHomeAddLongPress(event.rawX, event.rawY)) return false
                val runnable = Runnable {
                    homeAddLongPressRunnable = null
                    if (!canArmHomeAddLongPress(homeAddLongPressStartX, homeAddLongPressStartY)) return@Runnable
                    homeAddLongPressFired = true
                    haptic(surface)
                    showHomeAddMenu()
                }
                homeAddLongPressRunnable = runnable
                handler.postDelayed(runnable, android.view.ViewConfiguration.getLongPressTimeout().toLong() + 120L)
            }
            MotionEvent.ACTION_MOVE -> {
                val slop = maxOf(dp(18), android.view.ViewConfiguration.get(surface.context).scaledTouchSlop * 2)
                if (abs(event.rawX - homeAddLongPressStartX) > slop || abs(event.rawY - homeAddLongPressStartY) > slop) {
                    homeAddLongPressRunnable?.let { handler.removeCallbacks(it) }
                    homeAddLongPressRunnable = null
                }
            }
            MotionEvent.ACTION_UP, MotionEvent.ACTION_CANCEL -> {
                homeAddLongPressRunnable?.let { handler.removeCallbacks(it) }
                homeAddLongPressRunnable = null
                if (homeAddLongPressFired) {
                    homeAddLongPressFired = false
                    return true
                }
            }
        }
        return false
    }

    private fun canArmHomeAddLongPress(rawX: Float, rawY: Float): Boolean {
        if (homeAddMenuView?.isAttachedToWindow == true) return false
        if (libraryOpen || isWidgetUniversalSearchActive() || openPane != null) return false
        if (spaceBoardOverlay != null || homeLeftOverlay != null || widgetBoardView != null || widgetPickerView != null) return false
        if (keyboardSettingsOpen || homeEditMode || innerKeyboardEditMode || innerWallpaperEditMode) return false
        if (clockStylePickerView?.isAttachedToWindow == true || weatherStylePickerView?.isAttachedToWindow == true || weatherPlacementView?.isAttachedToWindow == true) return false
        if (themePaneHost.briefThemePickerShowing()) return false
        if (isInsideKeyboard(rawX, rawY) || isInsideKeyboardRevealZone(rawX, rawY) || isInsideTypingStrip(rawX, rawY)) return false
        return !isInsideHomeAddExcludedSurface(rawX, rawY)
    }

    private fun isInsideHomeAddExcludedSurface(rawX: Float, rawY: Float): Boolean {
        fun inside(view: View?): Boolean {
            val target = view ?: return false
            if (!target.isShown || target.width <= 0 || target.height <= 0) return false
            val loc = IntArray(2)
            target.getLocationOnScreen(loc)
            return rawX >= loc[0] && rawX <= loc[0] + target.width &&
                rawY >= loc[1] && rawY <= loc[1] + target.height
        }
        if (::favoritesDockFrameView.isInitialized && inside(favoritesDockFrameView)) return true
        return inside(clockWidgetFrameView) ||
            inside(weatherWidgetFrameView) ||
            inside(agendaWidgetFrameView) ||
            inside(briefWidgetFrameView) ||
            inside(if (::nowPlayingCardView.isInitialized) nowPlayingCardView else null)
    }

    private fun showHomeAddMenu() {
        if (!::contentFrame.isInitialized || homeAddMenuView?.isAttachedToWindow == true) return
        val overlay = FrameLayout(this).apply {
            isClickable = true
            setBackgroundColor(adjustAlpha(Color.BLACK, if (activeNeuTokens.mode == NeuMode.DARK) 0.28f else 0.14f))
            setOnClickListener { closeHomeAddMenu() }
        }
        val panel = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            isClickable = true
            clipChildren = false
            clipToPadding = false
            setPadding(dp(16), dp(15), dp(16), dp(16))
            background = homeAddPanelBackground()
            elevation = dp(20).toFloat()

            addView(LinearLayout(context).apply {
                orientation = LinearLayout.HORIZONTAL
                gravity = Gravity.CENTER_VERTICAL
                addView(LinearLayout(context).apply {
                    orientation = LinearLayout.VERTICAL
                    addView(TextView(context).apply {
                        text = "Add to Home"
                        textSize = 21f
                        typeface = Typeface.create("sans-serif-medium", Typeface.NORMAL)
                        includeFontPadding = false
                        setTextColor(activeNeuTokens.ink)
                    })
                    addView(mono("PRESS · PICK · PLACE", 8.3f, activeNeuTokens.inkFaint).apply {
                        letterSpacing = 0.16f
                        setPadding(0, dp(5), 0, 0)
                    })
                }, LinearLayout.LayoutParams(0, LinearLayout.LayoutParams.WRAP_CONTENT, 1f))
                addView(TextView(context).apply {
                    text = "×"
                    gravity = Gravity.CENTER
                    textSize = 18f
                    includeFontPadding = false
                    typeface = Typeface.create("sans-serif-medium", Typeface.NORMAL)
                    setTextColor(activeNeuTokens.inkDim)
                    background = Neu.drawable(activeNeuTokens, dp(15).toFloat(), NeuLevel.PRESSED_SM)
                    setOnClickListener {
                        haptic(this)
                        closeHomeAddMenu()
                    }
                }, LinearLayout.LayoutParams(dp(36), dp(36)))
            }, LinearLayout.LayoutParams(LinearLayout.LayoutParams.MATCH_PARENT, dp(46)).apply {
                bottomMargin = dp(12)
            })

            addView(LinearLayout(context).apply {
                orientation = LinearLayout.HORIZONTAL
                addView(homeAddWidgetCard(
                    glyph = "◷",
                    title = "Clock",
                    subtitle = if (clockWidgetVisible()) clockWidgetStyleName() else "Live time card",
                    accent = 0xFFC9A7FF.toInt(),
                    tall = true
                ) { addClockWidgetFromHomeMenu() }, LinearLayout.LayoutParams(0, dp(116), 1f).apply {
                    rightMargin = dp(8)
                })
                addView(homeAddWidgetCard(
                    glyph = "☼",
                    title = "Weather",
                    subtitle = if (weatherWidgetVisible()) "Choose style" else "Local forecast",
                    accent = 0xFFF5C451.toInt(),
                    tall = true
                ) { addWeatherWidgetFromHomeMenu() }, LinearLayout.LayoutParams(0, dp(116), 1f))
            }, LinearLayout.LayoutParams(LinearLayout.LayoutParams.MATCH_PARENT, dp(116)).apply {
                bottomMargin = dp(8)
            })

            addView(LinearLayout(context).apply {
                orientation = LinearLayout.HORIZONTAL
                addView(homeAddWidgetCard(
                    glyph = "›",
                    title = "Brief",
                    subtitle = if (briefWidgetVisible()) "Choose theme" else "Daily actions",
                    accent = 0xFF5FD0C4.toInt(),
                    tall = true
                ) { addBriefWidgetFromHomeMenu() }, LinearLayout.LayoutParams(0, dp(100), 1f).apply {
                    rightMargin = dp(8)
                })
                addView(homeAddWidgetCard(
                    glyph = "◌",
                    title = "Agenda",
                    subtitle = if (agendaWidgetVisible()) "On home" else "Next event",
                    accent = 0xFFFF8F8F.toInt(),
                    tall = true
                ) { addAgendaWidgetFromHomeMenu() }, LinearLayout.LayoutParams(0, dp(100), 1f))
            }, LinearLayout.LayoutParams(LinearLayout.LayoutParams.MATCH_PARENT, dp(100)).apply {
                bottomMargin = dp(12)
            })

            addView(homeAddAndroidWidgetsButton(), LinearLayout.LayoutParams(LinearLayout.LayoutParams.MATCH_PARENT, dp(60)))
        }
        overlay.addView(panel, FrameLayout.LayoutParams(
            minOf(resources.displayMetrics.widthPixels - dp(28), dp(430)),
            FrameLayout.LayoutParams.WRAP_CONTENT,
            Gravity.BOTTOM or Gravity.CENTER_HORIZONTAL
        ).apply {
            bottomMargin = if (!isUnfoldedInnerLayoutActive() && keyboardPlacement == KEYBOARD_PLACEMENT_WIDGET && !widgetKeyboardHidden) {
                widgetKeyboardSlotHeight() + dp(10)
            } else {
                dp(18)
            }
        })
        homeAddMenuView = overlay
        contentFrame.addView(overlay, FrameLayout.LayoutParams(FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.MATCH_PARENT))
        panel.translationY = dp(34).toFloat()
        panel.alpha = 0f
        overlay.alpha = 0f
        overlay.animate().alpha(1f).setDuration(140).start()
        panel.animate().alpha(1f).translationY(0f).setDuration(260)
            .setInterpolator(android.view.animation.OvershootInterpolator(0.55f))
            .start()
    }

    private fun closeHomeAddMenu() {
        val overlay = homeAddMenuView ?: return
        homeAddMenuView = null
        overlay.animate().alpha(0f).setDuration(130)
            .withEndAction { (overlay.parent as? ViewGroup)?.removeView(overlay) }
            .start()
    }

    private fun homeAddPanelBackground(): Drawable {
        val surface = GradientDrawable(GradientDrawable.Orientation.TOP_BOTTOM, intArrayOf(
            adjustAlpha(activeNeuTokens.baseHi, if (activeNeuTokens.mode == NeuMode.LIGHT) 0.92f else 0.92f),
            adjustAlpha(activeNeuTokens.base, if (activeNeuTokens.mode == NeuMode.LIGHT) 0.96f else 0.94f),
            adjustAlpha(activeNeuTokens.baseLo, if (activeNeuTokens.mode == NeuMode.LIGHT) 0.84f else 0.82f)
        )).apply {
            cornerRadius = dp(28).toFloat()
        }
        val rim = GradientDrawable().apply {
            setColor(Color.TRANSPARENT)
            cornerRadius = dp(28).toFloat()
            setStroke(dp(1), adjustAlpha(Color.WHITE, if (activeNeuTokens.mode == NeuMode.LIGHT) 0.24f else 0.10f))
        }
        return LayerDrawable(arrayOf(surface, rim))
    }

    private fun homeAddWidgetCard(
        glyph: String,
        title: String,
        subtitle: String,
        accent: Int,
        tall: Boolean,
        onClick: () -> Unit
    ): View = LinearLayout(this).apply {
        orientation = if (tall) LinearLayout.VERTICAL else LinearLayout.HORIZONTAL
        gravity = if (tall) Gravity.LEFT or Gravity.CENTER_VERTICAL else Gravity.CENTER_VERTICAL
        setPadding(dp(14), dp(12), dp(14), dp(12))
        background = Neu.drawable(activeNeuTokens, dp(22).toFloat(), NeuLevel.RAISED_SM)
        isClickable = true
        setOnClickListener {
            haptic(this)
            onClick()
        }
        val glyphView = TextView(context).apply {
            text = glyph
            gravity = Gravity.CENTER
            textSize = if (tall) 22f else 18f
            includeFontPadding = false
            typeface = Typeface.create("serif", Typeface.BOLD)
            setTextColor(accent)
            background = GradientDrawable(GradientDrawable.Orientation.TL_BR, intArrayOf(
                adjustAlpha(accent, if (activeNeuTokens.mode == NeuMode.LIGHT) 0.22f else 0.20f),
                adjustAlpha(activeNeuTokens.baseLo, if (activeNeuTokens.mode == NeuMode.LIGHT) 0.10f else 0.38f)
            )).apply {
                shape = GradientDrawable.OVAL
                setStroke(dp(1), adjustAlpha(accent, 0.28f))
            }
        }
        addView(glyphView, LinearLayout.LayoutParams(dp(if (tall) 42 else 38), dp(if (tall) 42 else 38)).apply {
            if (tall) bottomMargin = dp(12) else marginEnd = dp(12)
        })
        val labelBlock = LinearLayout(context).apply {
            orientation = LinearLayout.VERTICAL
            gravity = Gravity.CENTER_VERTICAL
            addView(TextView(context).apply {
                text = title
                textSize = if (tall) 15.4f else 15.8f
                typeface = Typeface.create("sans-serif-medium", Typeface.NORMAL)
                includeFontPadding = false
                setTextColor(activeNeuTokens.ink)
            })
            addView(TextView(context).apply {
                text = subtitle
                textSize = 10.2f
                includeFontPadding = false
                setTextColor(activeNeuTokens.inkDim)
                maxLines = 1
                ellipsize = android.text.TextUtils.TruncateAt.END
                setPadding(0, dp(4), 0, 0)
            })
        }
        val labelLp = if (tall) {
            LinearLayout.LayoutParams(LinearLayout.LayoutParams.MATCH_PARENT, LinearLayout.LayoutParams.WRAP_CONTENT)
        } else {
            LinearLayout.LayoutParams(0, LinearLayout.LayoutParams.WRAP_CONTENT, 1f)
        }
        addView(labelBlock, labelLp)
    }

