    private fun openClockStylePicker() {
        if (!::contentFrame.isInitialized || clockStylePickerView?.isAttachedToWindow == true) return
        val overlay = FrameLayout(this).apply {
            isClickable = true
            setBackgroundColor(adjustAlpha(Color.BLACK, if (activeNeuTokens.mode == NeuMode.DARK) 0.48f else 0.30f))
            setOnClickListener { closeClockStylePicker() }
        }
        val selected = clockWidgetStyleId()
        val panel = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            isClickable = true
            clipChildren = false
            clipToPadding = false
            setPadding(dp(16), dp(12), dp(16), dp(16))
            background = homeAddPanelBackground()
            elevation = dp(22).toFloat()
            addView(LinearLayout(context).apply {
                orientation = LinearLayout.HORIZONTAL
                gravity = Gravity.CENTER_VERTICAL
                addView(LinearLayout(context).apply {
                    orientation = LinearLayout.VERTICAL
                    addView(TextView(context).apply {
                        text = "Clock Themes"
                        textSize = 21f
                        typeface = Typeface.create("sans-serif-medium", Typeface.NORMAL)
                        includeFontPadding = false
                        setTextColor(activeNeuTokens.ink)
                    })
                    addView(mono("20 LIVE CLOCK WIDGET STYLES", 8.2f, activeNeuTokens.inkFaint).apply {
                        letterSpacing = 0.15f
                        setPadding(0, dp(5), 0, 0)
                    })
                }, LinearLayout.LayoutParams(0, LinearLayout.LayoutParams.WRAP_CONTENT, 1f))
                addView(TextView(context).apply {
                    text = "×"
                    gravity = Gravity.CENTER
                    textSize = 18f
                    includeFontPadding = false
                    typeface = Typeface.create("sans-serif-medium", Typeface.NORMAL)
                    setTextColor(activeNeuTokens.inkDim)
                    background = Neu.drawable(activeNeuTokens, dp(15).toFloat(), NeuLevel.PRESSED_SM)
                    setOnClickListener {
                        haptic(this)
                        closeClockStylePicker()
                    }
                }, LinearLayout.LayoutParams(dp(36), dp(36)))
            }, LinearLayout.LayoutParams(LinearLayout.LayoutParams.MATCH_PARENT, dp(48)).apply { bottomMargin = dp(10) })

            addView(ScrollView(context).apply {
                isVerticalScrollBarEnabled = false
                overScrollMode = View.OVER_SCROLL_NEVER
                addView(LinearLayout(context).apply {
                    orientation = LinearLayout.VERTICAL
                    ClockThemes.all.chunked(2).forEach { rowThemes ->
                        addView(LinearLayout(context).apply {
                            orientation = LinearLayout.HORIZONTAL
                            rowThemes.forEach { theme ->
                                addView(clockThemeCell(theme, selected == theme.id), LinearLayout.LayoutParams(0, dp(148), 1f).apply {
                                    marginEnd = if (theme != rowThemes.last()) dp(10) else 0
                                })
                            }
                            repeat(2 - rowThemes.size) { addView(View(context), LinearLayout.LayoutParams(0, dp(148), 1f)) }
                        }, LinearLayout.LayoutParams(LinearLayout.LayoutParams.MATCH_PARENT, dp(148)).apply { bottomMargin = dp(10) })
                    }
                }, FrameLayout.LayoutParams(FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.WRAP_CONTENT))
            }, LinearLayout.LayoutParams(LinearLayout.LayoutParams.MATCH_PARENT, 0, 1f))
        }
        overlay.addView(panel, FrameLayout.LayoutParams(
            minOf(resources.displayMetrics.widthPixels - dp(20), dp(520)),
            (resources.displayMetrics.heightPixels * 0.74f).toInt(),
            Gravity.BOTTOM or Gravity.CENTER_HORIZONTAL
        ))
        clockStylePickerView = overlay
        contentFrame.addView(overlay, FrameLayout.LayoutParams(FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.MATCH_PARENT))
        panel.translationY = dp(38).toFloat()
        panel.alpha = 0f
        overlay.alpha = 0f
        overlay.animate().alpha(1f).setDuration(140).start()
        panel.animate().alpha(1f).translationY(0f).setDuration(245).setInterpolator(DecelerateInterpolator()).start()
    }

    private fun clockThemeCell(theme: com.fran.teclas.clock.ClockThemeSpec, selected: Boolean): View =
        LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(dp(8), dp(8), dp(8), dp(8))
            background = Neu.drawable(activeNeuTokens, dp(18).toFloat(), if (selected) NeuLevel.RAISED else NeuLevel.PRESSED_SM)
            isClickable = true
            setOnClickListener {
                haptic(this)
                applyClockWidgetStyle(theme.id)
            }
            addView(ClockWidgetView(context).apply {
                themeId = theme.id
                accentColor = goKeyColor
                isDarkMode = activeNeuTokens.mode == NeuMode.DARK
                previewState = ClockState(1, 54, 0, true, false, "Tuesday", "Jul 21", 80, "Fort Myers")
            }, LinearLayout.LayoutParams(LinearLayout.LayoutParams.MATCH_PARENT, 0, 1f))
            addView(LinearLayout(context).apply {
                orientation = LinearLayout.HORIZONTAL
                gravity = Gravity.CENTER_VERTICAL
                addView(TextView(context).apply {
                    text = theme.label
                    textSize = 10.5f
                    maxLines = 1
                    ellipsize = android.text.TextUtils.TruncateAt.END
                    typeface = Typeface.create("sans-serif-medium", Typeface.NORMAL)
                    includeFontPadding = false
                    setTextColor(activeNeuTokens.ink)
                }, LinearLayout.LayoutParams(0, dp(24), 1f))
                addView(mono(if (theme.container == ClockContainer.GLASS_BOX) "GLASS" else "OPEN", 7.4f, if (selected) goKeyColor else activeNeuTokens.inkFaint).apply {
                    gravity = Gravity.CENTER
                    letterSpacing = 0.15f
                    background = Neu.drawable(activeNeuTokens, dp(9).toFloat(), NeuLevel.PRESSED_SM)
                    setPadding(dp(6), 0, dp(6), 0)
                }, LinearLayout.LayoutParams(LinearLayout.LayoutParams.WRAP_CONTENT, dp(22)))
            }, LinearLayout.LayoutParams(LinearLayout.LayoutParams.MATCH_PARENT, dp(26)).apply { topMargin = dp(6) })
        }

    private fun applyClockWidgetStyle(styleId: String) {
        val id = ClockThemes.byId(styleId).id
        prefs().edit()
            .putBoolean(homeScopedKey(CLOCK_WIDGET_VISIBLE_PREF), true)
            .putString(homeScopedKey(CLOCK_WIDGET_THEME_PREF), id)
            .apply()
        haptic(contentFrame)
        closeClockStylePicker()
        render()
    }

    private fun closeClockStylePicker() {
        val overlay = clockStylePickerView ?: return
        clockStylePickerView = null
        overlay.animate().alpha(0f).setDuration(130)
            .withEndAction { (overlay.parent as? ViewGroup)?.removeView(overlay) }
            .start()
    }

    private fun weatherWidgetStyleId(): String =
        prefs().getString(homeScopedKey(WEATHER_WIDGET_STYLE_PREF), WEATHER_STYLE_CLASSIC_ID) ?: WEATHER_STYLE_CLASSIC_ID

    private fun weatherWidgetStyleName(): String =
        if (weatherWidgetStyleId() == WEATHER_STYLE_CLASSIC_ID) "Classic" else weatherStyleById(weatherWidgetStyleId()).name

    private fun weatherWidgetVisible(): Boolean =
        prefs().getBoolean(homeScopedKey(ThemeRepository.WEATHER_VISIBLE_PREF), true)

    private fun briefWidgetVisible(): Boolean =
        prefs().getBoolean(homeScopedKey(ThemeRepository.BRIEF_VISIBLE_PREF), true)

    private fun weatherWidgetHasCustomPos(): Boolean =
        prefs().contains(homeScopedKey(WEATHER_WIDGET_POS_X_PREF)) && prefs().contains(homeScopedKey(WEATHER_WIDGET_POS_Y_PREF))

    private fun saveWeatherWidgetPos(x: Int, y: Int) {
        prefs().edit().putInt(homeScopedKey(WEATHER_WIDGET_POS_X_PREF), x).putInt(homeScopedKey(WEATHER_WIDGET_POS_Y_PREF), y).apply()
    }

    private fun buildWeatherWidgetFrame(context: Context): WeatherWidgetFrame {
        val frame = WeatherWidgetFrame(context)
        weatherWidgetFrameView = frame
        val styleId = weatherWidgetStyleId()
        if (styleId == WEATHER_STYLE_CLASSIC_ID) {
            // homeHeader() rebinds the weather lateinit views; the floating copy is built after
            // the column's invisible keeper, so updateClock() drives this live instance.
            val header = homeHeader().apply { installWeatherPickerLongPress() }
            frame.addView(header, FrameLayout.LayoutParams(FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.WRAP_CONTENT))
        } else {
            frame.clipChildren = true
            frame.clipToPadding = true
            refreshWeatherWidgetComposeData()
            frame.addView(ComposeView(context).apply {
                setBackgroundColor(Color.TRANSPARENT)
                setContent {
                    val data = weatherWidgetComposeData.value
                    if (data != null) {
                        Box(
                            modifier = Modifier
                                .fillMaxSize()
                                .padding(horizontal = 8.dp, vertical = 4.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            weatherStyleById(styleId).render(data, ComposeColor(goKeyColor), Modifier)
                        }
                    }
                }
                installWeatherPickerLongPress()
            }, FrameLayout.LayoutParams(FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.MATCH_PARENT))
            frame.isClickable = true
            frame.setOnClickListener {
                haptic(frame)
                if (hasWeatherPermission()) refreshWeather(force = true) else weatherPermissionLauncher.launch(android.Manifest.permission.ACCESS_COARSE_LOCATION)
            }
        }
        frame.installWeatherPickerLongPress()
        frame.elevation = dp(8).toFloat()
        return frame
    }

    private fun View.installWeatherPickerLongPress() {
        var startX = 0f
        var startY = 0f
        var fired = false
        var armed: Runnable? = null
        fun cancelHold(v: View) {
            armed?.let { v.removeCallbacks(it) }
            armed = null
        }
        setOnTouchListener { view, event ->
            when (event.actionMasked) {
                MotionEvent.ACTION_DOWN -> {
                    startX = event.rawX
                    startY = event.rawY
                    fired = false
                    cancelHold(view)
                    val r = Runnable {
                        armed = null
                        fired = true
                        view.parent?.requestDisallowInterceptTouchEvent(true)
                        haptic(view)
                        showWeatherWidgetManageMenu(view)
                    }
                    armed = r
                    view.postDelayed(r, android.view.ViewConfiguration.getLongPressTimeout().toLong())
                    false
                }
                MotionEvent.ACTION_MOVE -> {
                    val slop = maxOf(dp(18), android.view.ViewConfiguration.get(view.context).scaledTouchSlop * 2)
                    if (abs(event.rawX - startX) > slop || abs(event.rawY - startY) > slop) cancelHold(view)
                    fired
                }
                MotionEvent.ACTION_UP, MotionEvent.ACTION_CANCEL -> {
                    cancelHold(view)
                    view.parent?.requestDisallowInterceptTouchEvent(false)
                    if (fired) {
                        fired = false
                        true
                    } else {
                        false
                    }
                }
                else -> fired
            }
        }
        isLongClickable = true
        setOnLongClickListener { view ->
            haptic(view)
            showWeatherWidgetManageMenu(view)
            true
        }
        if (this is ViewGroup) {
            for (i in 0 until childCount) getChildAt(i).installWeatherPickerLongPress()
        }
    }

    private fun weatherWidgetFrameLayoutParams(): FrameLayout.LayoutParams {
        val classic = weatherWidgetStyleId() == WEATHER_STYLE_CLASSIC_ID
        val lp = if (classic) {
            FrameLayout.LayoutParams(weatherWidgetFreeformWidth(), FrameLayout.LayoutParams.WRAP_CONTENT)
        } else {
            FrameLayout.LayoutParams(weatherWidgetStyledWidth(), weatherWidgetStyledHeight(weatherWidgetStyleId()))
        }
        // Default = the header's flow position (content column padding), so an unset
        // position renders pixel-identically to the old fixed top header.
        if (isUnfoldedInnerLayoutActive()) {
            lp.leftMargin = 0
            lp.topMargin = dp(74)
        } else {
            lp.leftMargin = 0
            lp.topMargin = 0
        }
        return lp
    }

    private fun weatherWidgetFreeformWidth(): Int {
        val max = resources.displayMetrics.widthPixels.coerceAtLeast(dp(260))
        return minOf(max, dp(420)).coerceAtLeast(dp(280))
    }

    private fun weatherWidgetStyledWidth(): Int {
        val max = resources.displayMetrics.widthPixels.coerceAtLeast(dp(220))
        return minOf(max, dp(360)).coerceAtLeast(dp(240))
    }

    private fun weatherWidgetStyledHeight(styleId: String): Int {
        val category = weatherStyleById(styleId).category
        return when (category) {
            "Almanac" -> dp(156)
            "Dot Matrix" -> dp(128)
            else -> dp(122)
        }
    }

    private fun applyPersistedWeatherWidgetPos(frame: WeatherWidgetFrame) {
        if (!weatherWidgetHasCustomPos()) return
        val parent = frame.parent as? View ?: return
        if (parent.width <= 0 || frame.width <= 0 || frame.height <= 0) return
        val lp = frame.layoutParams as FrameLayout.LayoutParams
        if (lp.width == FrameLayout.LayoutParams.MATCH_PARENT) {
            lp.width = frame.width
            lp.rightMargin = 0
        }
        val x = prefs().getInt(homeScopedKey(WEATHER_WIDGET_POS_X_PREF), lp.leftMargin)
        val y = prefs().getInt(homeScopedKey(WEATHER_WIDGET_POS_Y_PREF), lp.topMargin)
        val (cx, cy) = clampWeatherWidgetPos(parent, frame.width, frame.height, x, y)
        // Placement-mode geometry can shift between sessions (keyboard mode, rotation);
        // re-apply the soft stack-avoid so a restored position doesn't bury the stack.
        val (rx, ry) = if (isUnfoldedInnerLayoutActive()) {
            cx to cy
        } else {
            resolveWeatherWidgetOverlap(parent, frame.width, frame.height, cx, cy) ?: (cx to cy)
        }
        lp.leftMargin = rx
        lp.topMargin = ry
        frame.layoutParams = lp
    }

    private fun viewTopIn(ancestor: View, v: View): Int {
        val a = IntArray(2); ancestor.getLocationInWindow(a)
        val b = IntArray(2); v.getLocationInWindow(b)
        return b[1] - a[1]
    }

    // Bottom edge the weather widget may not cross: the favorites dock top (the keyboard
    // widget sits below the dock, and in docked mode the strip/keyboard live outside this
    // frame entirely). Re-derived from live views, so a placement-mode re-render() is enough
    // to recompute the reserved region.
    private fun weatherWidgetBottomLimitIn(ancestor: View): Int {
        var limit = ancestor.height
        if (::favoritesDockFrameView.isInitialized) {
            val dock = favoritesDockFrameView
            if (dock.isShown && dock.height > 0) {
                val top = viewTopIn(ancestor, dock)
                if (top > 0) limit = minOf(limit, top - dp(4))
            }
        }
        return limit
    }

    private fun clampWeatherWidgetPos(ancestor: View, w: Int, h: Int, x: Int, y: Int): Pair<Int, Int> {
        val maxX = (ancestor.width - w).coerceAtLeast(0)
        val bottomLimit = if (isUnfoldedInnerLayoutActive()) ancestor.height else weatherWidgetBottomLimitIn(ancestor)
        val maxY = (bottomLimit - h).coerceAtLeast(0)
        return x.coerceIn(0, maxX) to y.coerceIn(0, maxY)
    }

    // Soft snap: only pulls onto the nearest 4×12 grid line when already within dp(12) of it.
    // Scoped to the weather widget — nothing else reads or reflows from this.
    private fun softSnapWeatherWidgetPos(ancestor: View, x: Int, y: Int): Pair<Int, Int> {
        val padL = dp(14)
        val padT = 0
        val gap = dp(10)
        val contentW = ancestor.width - padL * 2
        val contentH = ancestor.height - padT
        if (contentW <= 0 || contentH <= 0) return x to y
        val cellW = (contentW - gap * (HOME_GRID_COLUMNS - 1)) / HOME_GRID_COLUMNS.toFloat()
        val cellH = (contentH - gap * (HOME_GRID_ROWS - 1)) / HOME_GRID_ROWS.toFloat()
        val threshold = dp(12)
        var sx = x
        var sy = y
        for (col in 0 until HOME_GRID_COLUMNS) {
            val gx = padL + ((cellW + gap) * col).toInt()
            if (abs(x - gx) <= threshold) { sx = gx; break }
        }
        for (row in 0 until HOME_GRID_ROWS) {
            val gy = padT + ((cellH + gap) * row).toInt()
            if (abs(y - gy) <= threshold) { sy = gy; break }
        }
        return sx to sy
    }

    // Soft avoid for the contextual widget stack: nudge to the nearer clear side, or null
    // when the widget cannot fit anywhere around it (caller rejects the drop).
    private fun resolveWeatherWidgetOverlap(ancestor: View, w: Int, h: Int, x: Int, y: Int): Pair<Int, Int>? {
        if (!::nowPlayingCardView.isInitialized) return x to y
        val stack = nowPlayingCardView
        if (!stack.isShown || stack.height <= 0) return x to y
        val stackTop = viewTopIn(ancestor, stack)
        val stackBottom = stackTop + stack.height
        val overlaps = y < stackBottom && y + h > stackTop
        if (!overlaps) return x to y
        val above = stackTop - dp(4) - h
        val below = stackBottom + dp(4)
        val bottomLimit = weatherWidgetBottomLimitIn(ancestor)
        val candidates = mutableListOf<Int>()
        if (above >= 0) candidates.add(above)
        if (below + h <= bottomLimit) candidates.add(below)
        val best = candidates.minByOrNull { abs(it - y) } ?: return null
        return x to best
    }

    private fun moveWeatherWidget(frame: View, left: Int, top: Int) {
        val parent = frame.parent as? View ?: return
        val lp = frame.layoutParams as FrameLayout.LayoutParams
        val (x, y) = clampWeatherWidgetPos(parent, frame.width, frame.height, left, top)
        lp.leftMargin = x
        lp.topMargin = y
        frame.layoutParams = lp
    }

    private fun settleWeatherWidget(frame: View, fallbackX: Int, fallbackY: Int) {
        val parent = frame.parent as? View ?: return
        val lp = frame.layoutParams as FrameLayout.LayoutParams
        val (cx, cy) = clampWeatherWidgetPos(parent, frame.width, frame.height, lp.leftMargin, lp.topMargin)
        if (isUnfoldedInnerLayoutActive()) {
            lp.leftMargin = cx
            lp.topMargin = cy
            frame.layoutParams = lp
            saveWeatherWidgetPos(cx, cy)
            haptic(frame)
            return
        }
        val (sx, sy) = softSnapWeatherWidgetPos(parent, cx, cy)
        val (bx, by) = clampWeatherWidgetPos(parent, frame.width, frame.height, sx, sy)
        val resolved = resolveWeatherWidgetOverlap(parent, frame.width, frame.height, bx, by)
        if (resolved == null) {
            if (hapticsEnabled) frame.performHapticFeedback(HapticFeedbackConstants.REJECT)
            lp.leftMargin = fallbackX
            lp.topMargin = fallbackY
            frame.layoutParams = lp
            return
        }
        lp.leftMargin = resolved.first
        lp.topMargin = resolved.second
        frame.layoutParams = lp
        saveWeatherWidgetPos(resolved.first, resolved.second)
        haptic(frame)
    }

    private fun freezeWeatherWidgetWidthForDrag(frame: View) {
        val lp = frame.layoutParams as FrameLayout.LayoutParams
        if (lp.width == FrameLayout.LayoutParams.MATCH_PARENT && frame.width > 0) {
            lp.width = frame.width
            lp.rightMargin = 0
            frame.layoutParams = lp
        }
    }

    /**
     * Freeform-move host shared by the weather + brief widgets. The widget is LOCKED by default so a
     * vertical swipe passes through to the home (keeping the swipe-up-for-app-library gesture). A
     * DOUBLE-TAP unlocks "move mode" (scale + haptic + hint); then a drag repositions and re-locks on
     * release, or it auto-locks after a few idle seconds. Long-press (when locked) opens the picker.
     */
    private abstract inner class MovableWidgetFrame(context: Context) : FrameLayout(context) {
        protected var startRawX = 0f
        protected var startRawY = 0f
        protected var startLeft = 0
        protected var startTop = 0
        private var dragging = false
        private var moveMode = false
        private var lastTapMs = 0L
        private var longPressFired = false
        private var longPressRunnable: Runnable? = null
        private var singleTapRunnable: Runnable? = null
        private var autoLockRunnable: Runnable? = null

        /** Persist the settled position. */
        protected abstract fun onSettle(fallbackLeft: Int, fallbackTop: Int)
        /** Long-press action while locked (open the style/theme picker). */
        protected abstract fun onLongPress()
        /** Optional single-tap action while locked. Delayed so double-tap can enter move mode. */
        protected open fun handlesLockedSingleTap(): Boolean = false
        protected open fun onLockedSingleTap() {}
        protected open fun lockedLongPressDelayMs(): Long = 700L
        protected open fun lockedLongPressCancelSlopPx(): Int = dp(6)
        protected open fun moveDuringDrag(left: Int, top: Int) = moveWeatherWidget(this, left, top)

        protected fun dispatchCancelToChildren() {
            val t = android.os.SystemClock.uptimeMillis()
            val cancel = MotionEvent.obtain(t, t, MotionEvent.ACTION_CANCEL, 0f, 0f, 0)
            super.dispatchTouchEvent(cancel); cancel.recycle()
        }

        private fun cancelPickerLongPress() { longPressRunnable?.let { removeCallbacks(it) }; longPressRunnable = null }
        private fun cancelLockedSingleTap() { singleTapRunnable?.let { removeCallbacks(it) }; singleTapRunnable = null }
        private fun armAutoLock() {
            autoLockRunnable?.let { removeCallbacks(it) }
            val r = Runnable { autoLockRunnable = null; exitMoveMode() }
            autoLockRunnable = r; postDelayed(r, 5_000L)
        }

        private fun enterMoveMode() {
            if (moveMode) return
            moveMode = true
            if (hapticsEnabled) performHapticFeedback(HapticFeedbackConstants.LONG_PRESS)
            animate().scaleX(1.03f).scaleY(1.03f).setDuration(110).start()
            elevation = dp(16).toFloat()
            Toast.makeText(this@MainActivity, "Drag to move — locks when you let go", Toast.LENGTH_SHORT).show()
            armAutoLock()
        }

        private fun exitMoveMode() {
            autoLockRunnable?.let { removeCallbacks(it) }; autoLockRunnable = null
            if (!moveMode) return
            moveMode = false
            weatherWidgetDragging = false
            animate().scaleX(1f).scaleY(1f).setDuration(110).start()
            elevation = dp(8).toFloat()
        }

        override fun dispatchTouchEvent(event: MotionEvent): Boolean {
            when (event.actionMasked) {
                MotionEvent.ACTION_DOWN -> {
                    startRawX = event.rawX; startRawY = event.rawY
                    val lp = layoutParams as FrameLayout.LayoutParams
                    startLeft = lp.leftMargin; startTop = lp.topMargin
                    dragging = false; longPressFired = false
                    cancelPickerLongPress()
                    val now = android.os.SystemClock.uptimeMillis()
                    val doubleTap = now - lastTapMs < 280
                    lastTapMs = now
                    if (doubleTap && !moveMode) {
                        cancelLockedSingleTap()
                        enterMoveMode()
                        parent?.requestDisallowInterceptTouchEvent(true)
                        return true
                    }
                    if (moveMode) {
                        parent?.requestDisallowInterceptTouchEvent(true)
                        armAutoLock()
                    } else {
                        // Locked: keep the long-press → picker, but DON'T disallow parent intercept,
                        // so a vertical swipe still reaches the home (app-library gesture).
                        val r = Runnable {
                            longPressRunnable = null; longPressFired = true
                            dispatchCancelToChildren()
                            if (hapticsEnabled) performHapticFeedback(HapticFeedbackConstants.LONG_PRESS)
                            onLongPress()
                        }
                        longPressRunnable = r
                        // A deliberately long, tight hold (≈700ms) so a glance-touch or the start of
                        // a swipe never trips the picker — only an intentional press-and-wait does.
                        postDelayed(r, lockedLongPressDelayMs())
                    }
                }
                MotionEvent.ACTION_MOVE -> {
                    if (!moveMode) {
                        // A touch that starts drifting is a swipe, not a hold → cancel the picker timer
                        // so the gesture reaches the home cleanly.
                        val holdSlop = lockedLongPressCancelSlopPx()
                        if ((abs(event.rawX - startRawX) > holdSlop || abs(event.rawY - startRawY) > holdSlop)) cancelPickerLongPress()
                        return super.dispatchTouchEvent(event)  // swipe passes through
                    }
                    if (longPressFired) return true
                    val dx = (event.rawX - startRawX).toInt()
                    val dy = (event.rawY - startRawY).toInt()
                    if (!dragging && (abs(dx) > dp(4) || abs(dy) > dp(4))) {
                        dragging = true
                        weatherWidgetDragging = true
                        freezeWeatherWidgetWidthForDrag(this)
                        dispatchCancelToChildren()
                    }
                    if (dragging) { moveDuringDrag(startLeft + dx, startTop + dy); armAutoLock() }
                    return true
                }
                MotionEvent.ACTION_UP, MotionEvent.ACTION_CANCEL -> {
                    cancelPickerLongPress()
                    if (longPressFired) { longPressFired = false; return true }
                    if (moveMode) {
                        parent?.requestDisallowInterceptTouchEvent(false)
                        if (dragging) {
                            dragging = false
                            onSettle(startLeft, startTop)
                            exitMoveMode()
                            return true
                        }
                        armAutoLock()   // tap in move mode without a drag: stay armed
                        return true
                    }
                    if (event.actionMasked == MotionEvent.ACTION_UP && handlesLockedSingleTap()) {
                        val tapSlop = maxOf(dp(8), android.view.ViewConfiguration.get(context).scaledTouchSlop)
                        val stillTap = abs(event.rawX - startRawX) <= tapSlop && abs(event.rawY - startRawY) <= tapSlop
                        if (stillTap) {
                            cancelLockedSingleTap()
                            val r = Runnable {
                                singleTapRunnable = null
                                onLockedSingleTap()
                            }
                            singleTapRunnable = r
                            postDelayed(r, 290L)
                            return true
                        }
                    }
                }
            }
            return super.dispatchTouchEvent(event)
        }
    }

    // Drag/long-press host for the weather widget. Same dispatchTouchEvent pattern as
    // HomeTileFrame, but always active: tap falls through to the header's refresh click,
    // a dp(4) slop starts the drag, and the standard long-press timeout opens the picker.
    private inner class WeatherWidgetFrame(context: Context) : MovableWidgetFrame(context) {
        private var persistedPosApplied = false

        init {
            clipChildren = false
            clipToPadding = false
            isClickable = true
            isLongClickable = true
        }

        override fun onLayout(changed: Boolean, l: Int, t: Int, r: Int, b: Int) {
            super.onLayout(changed, l, t, r, b)
            if (!persistedPosApplied && width > 0 && ((parent as? View)?.width ?: 0) > 0) {
                persistedPosApplied = true
                post { applyPersistedWeatherWidgetPos(this) }
            }
        }

        override fun onSettle(fallbackLeft: Int, fallbackTop: Int) = settleWeatherWidget(this, fallbackLeft, fallbackTop)
        override fun lockedLongPressDelayMs(): Long = android.view.ViewConfiguration.getLongPressTimeout().toLong()
        override fun lockedLongPressCancelSlopPx(): Int = maxOf(dp(18), android.view.ViewConfiguration.get(this@MainActivity).scaledTouchSlop * 2)
        override fun onLongPress() = showWeatherWidgetManageMenu(this)
    }

    // ── Daily brief widget ───────────────────────────────────────────────────
    // Freeform like the weather widget (drag anywhere, per-surface persisted position),
    // but ephemeral: it exists only while a morning/evening edition is live and undismissed.

    private fun saveBriefWidgetPos(x: Int, y: Int) {
        prefs().edit().putInt(homeScopedKey(BRIEF_POS_X_PREF), x).putInt(homeScopedKey(BRIEF_POS_Y_PREF), y).apply()
    }

    internal fun briefThemeId(): String =
        com.fran.teclas.brief.BriefThemes
            .themeForPref(prefs().getString(homeScopedKey(BRIEF_THEME_PREF), BRIEF_THEME_GLASS))
            .id
            .toString()

    /** Open a source thread: the exact notification if still live, else the app, else say so. */
    private fun openThread(pkg: String, key: String) {
        val intent = TeclasNotificationListener.notificationIntents[key]
        if (intent != null) { runCatching { intent.send() }.onSuccess { return } }
        if (pkg.isNotBlank()) {
            packageManager.getLaunchIntentForPackage(pkg)?.let { startSafeIntent(it, "Couldn't open the app"); return }
        }
        Toast.makeText(this, "That conversation is no longer available.", Toast.LENGTH_SHORT).show()
    }

    private fun openBriefRow(row: com.fran.teclas.brief.DailyBrief.Row) = openThread(row.pkg, row.key)

    // Natural recall → things to do with people: commitments harvested from conversations (during
    // the brief pass; no background work) plus timed calendar events. "what to do today" surfaces
    // the day's plans generally; naming a person keyword-matches. Tap opens the thread / event.
    private fun searchCommitmentResults(q: String): List<SearchResult> {
        val lower = q.lowercase(Locale.US)
        val general = listOf("what to do", "to do", "todo", "plans", "plan", "anything", "coming up", "upcoming", "my day")
            .any { lower.contains(it) }
        val recall = general || looksLikeAiQuestion(lower) ||
            listOf("supposed", "remind", "owe", "was i", "did i", "need to", "meant to", "dinner", "with ", "doing")
                .any { lower.contains(it) }
        if (!recall) return emptyList()

        val out = mutableListOf<SearchResult>()
        val commits = if (general) com.fran.teclas.brief.CommitmentStore.all(prefs()).take(3)
            else com.fran.teclas.brief.CommitmentStore.search(prefs(), q)
        commits.forEach { c ->
            out.add(SearchResult(
                if (c.person.isBlank()) c.text else "${c.person} · ${c.text}",
                if (c.pkg.isNotBlank()) "From your conversations · tap to open" else "From your conversations",
                0xFF5FD0C4.toInt(), SearchKind.MESSAGE, null,
            ) { openThread(c.pkg, c.key) })
        }

        // Calendar plans with people = timed (non-all-day) upcoming events. General query → today's;
        // a person/keyword query → matching titles/locations over the next week.
        val now = System.currentTimeMillis()
        val todayEnd = java.util.Calendar.getInstance().apply {
            set(java.util.Calendar.HOUR_OF_DAY, 23); set(java.util.Calendar.MINUTE, 59)
        }.timeInMillis
        val horizon = if (general) todayEnd else now + 7L * 24 * 3600_000L
        val terms = lower.split(Regex("[^a-z0-9]+")).filter { it.length >= 3 &&
            it !in setOf("what", "with", "the", "did", "was", "todo", "plans", "plan", "today", "tonight", "have", "any", "for", "and", "doing", "supposed", "need") }
        calendarEvents.asSequence()
            .filter { it.beginMs in now..horizon && (it.endMs - it.beginMs) in 1..(23L * 3600_000L) }
            .filter { ev -> general || terms.isEmpty() || terms.any { "${ev.title} ${ev.location}".lowercase().contains(it) } }
            .take(3)
            .forEach { ev ->
                out.add(SearchResult(
                    ev.title,
                    listOf(ev.timeLabel, ev.location).filter { it.isNotBlank() }.joinToString(" · "),
                    0xFFFF8F8F.toInt(), SearchKind.CALENDAR, null,
                ) { openCalendarEventOrRequest(ev) })
            }
        return out.take(5)
    }

    private data class AgendaEntry(
        val label: String,
        val title: String,
        val subtitle: String,
        val accent: Int,
        val timeMs: Long,
        val event: CalendarEvent? = null,
        val briefItem: BriefItem? = null
    )

    private fun agendaEntries(limit: Int = 4): List<AgendaEntry> {
        val now = System.currentTimeMillis()
        val entries = mutableListOf<AgendaEntry>()
        calendarEvents
            .filter { now >= it.beginMs && now < it.endMs }
            .sortedBy { it.endMs }
            .take(1)
            .forEach { event ->
                entries += AgendaEntry(
                    label = "HAPPENING NOW",
                    title = event.title,
                    subtitle = "Until ${agendaClock(event.endMs)}${event.location.takeIf { it.isNotBlank() }?.let { " · $it" }.orEmpty()}",
                    accent = 0xFFFF5A3C.toInt(),
                    timeMs = event.beginMs,
                    event = event
                )
            }
        calendarEvents
            .filter { it.beginMs > now }
            .sortedBy { it.beginMs }
            .take(3)
            .forEachIndexed { index, event ->
                entries += AgendaEntry(
                    label = if (index == 0) "UP NEXT" else event.dayLabel.ifBlank { "LATER" }.uppercase(Locale.US),
                    title = event.title,
                    subtitle = listOf(event.timeLabel, event.location).filter { it.isNotBlank() }.joinToString(" · "),
                    accent = if (index == 0) 0xFFF5C451.toInt() else activeNeuTokens.inkDim,
                    timeMs = event.beginMs,
                    event = event
                )
            }
        if (hasBriefRepository()) {
            briefRepository.brief.value.items
                .filterNot { it.category == BriefCategory.WEATHER || it.category == BriefCategory.MUSIC || it.category == BriefCategory.CALENDAR }
                .take(3)
                .forEach { item ->
                    entries += AgendaEntry(
                        label = when (item.category) {
                            BriefCategory.MESSAGE -> "REPLY"
                            BriefCategory.EMAIL -> "INBOX"
                            BriefCategory.CALL -> "CALL"
                            else -> "ACTION"
                        },
                        title = item.title,
                        subtitle = item.subtitle,
                        accent = when (item.category) {
                            BriefCategory.MESSAGE -> 0xFF5FD0C4.toInt()
                            BriefCategory.EMAIL -> 0xFFEA4335.toInt()
                            BriefCategory.CALL -> 0xFF57C98A.toInt()
                            else -> 0xFF9B72F0.toInt()
                        },
                        timeMs = item.signal?.timestamp ?: now,
                        briefItem = item
                    )
                }
        }
        return entries
            .distinctBy { it.event?.eventId?.let { id -> "cal:$id" } ?: it.briefItem?.signalRef ?: "${it.label}:${it.title}" }
            .sortedWith(compareBy<AgendaEntry> { it.briefItem != null }.thenBy { it.timeMs })
            .take(limit)
    }

    private fun agendaClock(ms: Long): String =
        LocalDateTime.ofInstant(Instant.ofEpochMilli(ms), ZoneId.systemDefault())
            .format(DateTimeFormatter.ofPattern("h:mm a", Locale.US))
            .lowercase(Locale.US)

    private fun buildAgendaWidgetFrame(context: Context): View? {
        val cardLayout = isUnfoldedInnerLayoutActive()
        val entries = agendaEntries(limit = if (cardLayout) 2 else 1)
        val entry = entries.firstOrNull() ?: return null
        val frame = AgendaWidgetFrame(context)
        agendaWidgetFrameView = frame
        frame.elevation = dp(if (cardLayout) 8 else 5).toFloat()
        if (cardLayout) {
            frame.background = ColorDrawable(Color.TRANSPARENT)
            frame.addView(foldAwareGlassPlate(context, radiusDp = 24), FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.MATCH_PARENT)
            frame.addView(agendaCardContent(context, entries), FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.MATCH_PARENT)
        } else {
            frame.background = agendaStripBackground()
            val content = LinearLayout(context).apply {
                orientation = LinearLayout.HORIZONTAL
                gravity = Gravity.CENTER_VERTICAL
                setPadding(dp(13), 0, dp(12), 0)
                isClickable = false
                background = briefRowRipple(16)
                addView(View(context).apply {
                    background = GradientDrawable().apply {
                        shape = GradientDrawable.OVAL
                        setColor(entry.accent)
                    }
                }, LinearLayout.LayoutParams(dp(7), dp(7)).apply { marginEnd = dp(9) })
                addView(mono(agendaStripLabel(entry), 8.6f, entry.accent).apply {
                    letterSpacing = 0.12f
                    gravity = Gravity.CENTER_VERTICAL
                    includeFontPadding = false
                }, LinearLayout.LayoutParams(LinearLayout.LayoutParams.WRAP_CONTENT, LinearLayout.LayoutParams.MATCH_PARENT).apply { marginEnd = dp(10) })
                addView(TextView(context).apply {
                    text = entry.title
                    textSize = 12.8f
                    includeFontPadding = false
                    gravity = Gravity.CENTER_VERTICAL
                    typeface = Typeface.create("sans-serif-medium", Typeface.NORMAL)
                    setTextColor(activeNeuTokens.ink)
                    maxLines = 1
                    ellipsize = android.text.TextUtils.TruncateAt.END
                }, LinearLayout.LayoutParams(0, LinearLayout.LayoutParams.MATCH_PARENT, 1f))
                addView(TextView(context).apply {
                    text = entry.subtitle
                    textSize = 10.4f
                    includeFontPadding = false
                    gravity = Gravity.CENTER_VERTICAL or Gravity.RIGHT
                    setTextColor(activeNeuTokens.inkDim)
                    maxLines = 1
                    ellipsize = android.text.TextUtils.TruncateAt.END
                }, LinearLayout.LayoutParams(dp(86), LinearLayout.LayoutParams.MATCH_PARENT).apply { marginStart = dp(8) })
            }
            frame.addView(content, FrameLayout.LayoutParams(FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.MATCH_PARENT))
        }
        return frame
    }

