    // ── On-device semantic search ────────────────────────────────────────────
    // EmbeddingGemma cosine matches over apps + settings. The generative-free path:
    // embeddings only, so it can run on every typing pause with no cloud and no quota.

    internal fun semanticSearchEnabled(): Boolean = prefs().getBoolean(SEMANTIC_SEARCH_PREF, false)

    private fun semanticIndexItems(): List<com.fran.teclas.semantic.SemanticItem> {
        val items = mutableListOf<com.fran.teclas.semantic.SemanticItem>()
        apps.forEach { app ->
            val text = if (app.shortName.isNotBlank() && !app.label.contains(app.shortName, ignoreCase = true))
                "${app.label} (${app.shortName})" else app.label
            items.add(com.fran.teclas.semantic.SemanticItem("app:${app.packageName}", text))
        }
        settingSearchEntries().forEach { entry ->
            items.add(com.fran.teclas.semantic.SemanticItem(
                "setting:${entry.title}",
                "Launcher setting: ${entry.title}. ${entry.keywords.joinToString(", ")}"
            ))
        }
        // Personal corpus: hub messages + upcoming events. Only vectors and notification/event
        // ids are persisted — never the text itself. Contacts stay string-matched (names are
        // proper nouns; embeddings add nothing there).
        messages.sortedByDescending { it.lastUpdated }.take(40).forEach { msg ->
            items.add(com.fran.teclas.semantic.SemanticItem(
                "msg:${msg.key}",
                "Message from ${msg.sender} in ${appLabel(msg.packageName)}: ${msg.preview}"
            ))
        }
        calendarEvents.take(20).forEach { event ->
            val place = if (event.location.isNotBlank()) " at ${event.location}" else ""
            items.add(com.fran.teclas.semantic.SemanticItem(
                "cal:${event.eventId}",
                "Calendar event: ${event.title}$place. ${event.dayLabel} ${event.timeLabel}"
            ))
        }
        return items
    }

    /** Debounced incremental re-embed after hub/calendar data moves (notifications churn fast;
     *  the hash check makes unchanged items free, so this only pays for genuinely new content). */
    private fun scheduleSemanticIndexRefresh() {
        if (!semanticSearchEnabled()) return
        semanticIndexDebounce?.let { handler.removeCallbacks(it) }
        val r = Runnable { semanticIndexDebounce = null; rebuildSemanticIndex() }
        semanticIndexDebounce = r
        handler.postDelayed(r, 5_000L)
    }

    /** Incrementally (re)embeds apps + settings. Cheap no-op when nothing changed. */
    private fun rebuildSemanticIndex() {
        if (!semanticSearchEnabled()) return
        val items = semanticIndexItems() // built on main: reads prefs/fields, no I/O
        mediaUiScope.launch {
            withContext(Dispatchers.IO) {
                runCatching { com.fran.teclas.semantic.SemanticSearchEngine.ensureIndex(this@MainActivity, items) }
                // Space cold-start priors ride on the same vectors — recompute after the index.
                runCatching {
                    com.fran.teclas.predict.SemanticPriors.rebuild(
                        this@MainActivity, com.fran.teclas.predict.SpaceManager.spaces(this@MainActivity)
                    )
                }
            }
        }
    }

    private fun scheduleSemanticSearch() {
        semanticSearchDebounce?.let { handler.removeCallbacks(it) }
        val q = query.trim()
        if (q.length < 3 || !semanticSearchEnabled()) {
            if (semanticQuickResults.isNotEmpty()) { semanticQuickResults = emptyList(); semanticQuickQuery = "" }
            return
        }
        if (q == semanticQuickQuery) return
        val r = Runnable {
            semanticSearchDebounce = null
            mediaUiScope.launch {
                val hits = withContext(Dispatchers.IO) {
                    runCatching {
                        com.fran.teclas.semantic.SemanticSearchEngine.search(this@MainActivity, q, topK = 6, minScore = 0.35f)
                    }.getOrDefault(emptyList())
                }
                if (query.trim() != q) return@launch   // query moved on
                val installed = apps.associateBy { it.packageName }
                val settingsByTitle = settingSearchEntries().associateBy { it.title }
                val messagesByKey = messages.associateBy { it.key }
                val eventsById = calendarEvents.associateBy { it.eventId.toString() }
                semanticQuickQuery = q
                semanticQuickResults = hits.mapNotNull { hit ->
                    when {
                        hit.key.startsWith("app:") -> installed[hit.key.removePrefix("app:")]?.let { app ->
                            SearchResult(app.label, "Open", app.brandColor, SearchKind.APP, app.toPaneTarget())
                        }
                        hit.key.startsWith("setting:") -> settingsByTitle[hit.key.removePrefix("setting:")]?.let { entry ->
                            SearchResult(entry.title, entry.state, goKeyColor, SearchKind.SETTING, null) { entry.perform() }
                        }
                        hit.key.startsWith("msg:") -> messagesByKey[hit.key.removePrefix("msg:")]?.let { msg ->
                            val kind = if (msg.kind == HUB_KIND_EMAIL) SearchKind.EMAIL else SearchKind.MESSAGE
                            SearchResult(msg.sender, "${msg.preview} . ${appLabel(msg.packageName)}", contextColor(msg), kind, msg.toPaneTarget())
                        }
                        hit.key.startsWith("cal:") -> eventsById[hit.key.removePrefix("cal:")]?.let { event ->
                            SearchResult(
                                event.title,
                                "${event.timeLabel}${if (event.location.isNotBlank()) " . ${event.location}" else ""}",
                                0xFFFF8F8F.toInt(), SearchKind.CALENDAR, null
                            ) { openCalendarEventOrRequest(event) }
                        }
                        else -> null
                    }
                }
                refreshSearchResultsUi()
            }
        }
        semanticSearchDebounce = r
        handler.postDelayed(r, 300L)
    }

    /** Debounced rich-answer lookup. Free keyless sources answer first (weather, crypto, currency,
     *  definitions) — those work on a fresh install with no setup and cost nothing. Brave is the
     *  fallback for what only it does, and every Brave fire is TWO metered requests against a
     *  ~1,000/month credit, so it stays gated on intent. */
    private fun scheduleBraveRichSearch() {
        braveRichDebounce?.let { handler.removeCallbacks(it) }
        val q = query.trim()
        val key = prefs().getString(BraveSearchApi.KEY_PREF, null)?.trim().orEmpty()
        val freeIntent = freeAnswerIntent(q) != null
        if (q.length < 2 || !(freeIntent || mayHaveRichIntent(q) || dictionaryWordFor(q) != null)) {
            if (braveRichAnswer != null || braveRichQuery.isNotEmpty()) { braveRichAnswer = null; braveRichQuery = "" }
            return
        }
        if (q == braveRichQuery) return
        val r = Runnable {
            braveRichDebounce = null
            mediaUiScope.launch {
                val answer = withContext(Dispatchers.IO) {
                    // ── Free, keyless sources first. No key, no metering, works out of the box. ──
                    freeAnswer(q)?.let { return@withContext it }
                    // Word-shaped queries hit the free dictionary — no Brave credit spent.
                    dictionaryWordFor(q)?.let { word ->
                        runCatching { DictionaryApi.define(word) }.getOrNull()?.let { return@withContext it }
                    }
                    // ── Brave: only for verticals no free API covers (stocks, landmarks, POI). ──
                    if (key.isBlank() || !mayHaveRichIntent(q)) return@withContext null
                    // Resolved off the main thread: bare "weather" may need a geocoder round-trip.
                    val effective = resolveBraveRichQuery(q) ?: return@withContext null
                    // Location headers turn on Brave's POI block and localize weather/sports.
                    val loc = AgenticLocation.lastKnown(this@MainActivity)
                    runCatching { BraveSearchApi.fetchRich(effective, key, loc?.latitude, loc?.longitude) }.getOrNull()
                }
                if (query.trim() != q) return@launch   // query moved on
                braveRichQuery = q
                braveRichAnswer = answer
                // A landmark card offers a ride ONLY when the user is actually in that city —
                // searching "eiffel tower" to read about it shouldn't push an Uber unless you're
                // standing in Paris. Resolved off-main: geocode the landmark, measure the distance.
                braveRideOffer = if (answer?.vertical == "landmark") resolveLandmarkRide(answer.headline) else null
                // Also on a null answer — see scheduleSportsSearch: retiring the card is a change.
                refreshSearchResultsUi()
            }
        }
        braveRichDebounce = r
        handler.postDelayed(r, 450L)
    }

    /** A ride offer for a landmark the user is near, or null when they're elsewhere / no fix.
     *  Blocking (geocoder) — call off the main thread. */
    private fun resolveLandmarkRide(name: String): RideOffer? {
        val here = AgenticLocation.lastKnown(this) ?: return null
        val there = runCatching {
            @Suppress("DEPRECATION")
            android.location.Geocoder(this, Locale.getDefault()).getFromLocationName(name, 1)?.firstOrNull()
        }.getOrNull() ?: return null
        val out = FloatArray(1)
        android.location.Location.distanceBetween(here.latitude, here.longitude, there.latitude, there.longitude, out)
        // Within ~40 km reads as "in the same city / metro" — the case where a ride makes sense.
        return if (out[0] <= 40_000f) RideOffer(name, there.latitude, there.longitude) else null
    }

    internal data class RideOffer(val name: String, val lat: Double, val lng: Double)
    internal var braveRideOffer: RideOffer? = null

    // Nearby places (Google Places) for the live query. Held in memory only — Google's terms
    // permit storing place IDs but not the rest of the payload.
    private var placesDebounce: Runnable? = null
    private var placesQuery: String = ""            // fetch key (query + refinement) — dedupes calls
    private var placesBaseQuery: String = ""        // the typed query the card belongs to
    private var placesRefinement: String? = null    // selected chip, e.g. "Sushi" — acts as a tab
    private var placesResults: List<PlacesApi.Place> = emptyList()

    /** Which free keyless source (if any) answers [q]. Pure string work — safe per keystroke. */
    private enum class FreeAnswer { WEATHER, CRYPTO, CURRENCY }

    private fun freeAnswerIntent(q: String): FreeAnswer? {
        val lower = q.lowercase(Locale.US).trim()
        if (lower.isBlank()) return null
        if (CurrencyApi.parse(lower) != null) return FreeAnswer.CURRENCY
        val words = lower.split(' ').filter { it.isNotBlank() }
        // "btc", "bitcoin price" — a coin term, alone or with a price/quote qualifier.
        val coinWord = words.firstOrNull { CryptoApi.idFor(it) != null }
        if (coinWord != null && words.all {
                it == coinWord || it in setOf("price", "quote", "value", "chart", "usd", "rate")
            }) return FreeAnswer.CRYPTO
        if (lower == "weather" || lower == "forecast" ||
            lower.startsWith("weather ") || lower.startsWith("forecast ") ||
            lower.startsWith("weather in ") || lower.contains(" weather")) return FreeAnswer.WEATHER
        return null
    }

    /** Resolve [q] via a free keyless API. Blocking — call off the main thread. */
    private fun freeAnswer(q: String): BraveSearchApi.RichAnswer? {
        val lower = q.lowercase(Locale.US).trim()
        return when (freeAnswerIntent(q)) {
            FreeAnswer.CURRENCY -> CurrencyApi.parse(lower)?.let { runCatching { CurrencyApi.card(it) }.getOrNull() }
            FreeAnswer.CRYPTO -> lower.split(' ').firstNotNullOfOrNull { w ->
                if (CryptoApi.idFor(w) != null) runCatching { CryptoApi.card(w) }.getOrNull() else null
            }
            FreeAnswer.WEATHER -> {
                // "weather in bogota" → that city; bare "weather" → wherever you are.
                val place = lower.removePrefix("weather in ").removePrefix("forecast in ")
                    .removePrefix("weather ").removePrefix("forecast ")
                    .removeSuffix(" weather").removeSuffix(" forecast").trim()
                    .takeIf { it.isNotBlank() && it != "weather" && it != "forecast" }
                val loc = if (place == null) AgenticLocation.lastKnown(this) else null
                if (place == null && loc == null) null
                else runCatching { WeatherApi.card(place, loc?.latitude, loc?.longitude) }.getOrNull()
            }
            null -> null
        }
    }

    /** Cheap main-thread pre-gate: could [q] resolve to a BRAVE lookup at all? Anything a free
     *  keyless API already answers is excluded here — Brave's metered credit is reserved for the
     *  verticals only it covers (stocks, landmarks, POI without a Places key). */
    private fun mayHaveRichIntent(q: String): Boolean {
        val lower = q.lowercase(Locale.US)
        // Free sources own these outright — never spend two Brave requests on them.
        if (freeAnswerIntent(q) != null) return false
        // Local intent goes to Places when it's configured — richer answer, and its free tier is
        // separate, so don't spend two Brave requests on a POI Places does better.
        val localToPlaces = looksLikeLocalIntent(lower) && PlacesApi.isConfigured(prefs())
        if (localToPlaces) return false
        return lower in BraveSearchApi.STOCK_TERMS ||
            looksLikeTicker(q) || looksLikeLocalIntent(lower) || BraveSearchApi.matchesLandmark(lower) ||
            looksLikeRichIntent(q)
    }

    /** The word to define for [q], or null. Definitions are OPT-IN only — "define:word" (or the
     *  spoken forms "define word" / "meaning of word"). A bare word used to define itself, which
     *  meant ordinary searches got a dictionary card they never asked for; typing a word is
     *  almost always launch/search intent, not vocabulary curiosity. */
    private fun dictionaryWordFor(q: String): String? {
        val lower = q.lowercase(Locale.US).trim()
        val word = when {
            lower.startsWith("define:") -> lower.removePrefix("define:").trim()
            lower.startsWith("define ") -> lower.removePrefix("define ").trim()
            lower.startsWith("meaning of ") -> lower.removePrefix("meaning of ").trim()
            else -> return null
        }
        if (word.length < 3 || !word.all { it.isLetter() }) return null
        return word
    }

    /** "AAPL", "Tsla" — a short letters-only token the user deliberately capitalized reads as a
     *  ticker. A miss just means Brave returns no hint; nothing is shown. */
    private fun looksLikeTicker(q: String): Boolean =
        q.length in 2..5 && q.all { it.isLetter() } && q.count { it.isUpperCase() } >= 2

    /** "nearest best buy", "coffee near me" — place lookups Brave can answer with a POI. */
    private fun looksLikeLocalIntent(lower: String): Boolean =
        listOf("near me", "nearest ", "closest ", "nearby", "open now").any { lower.contains(it) }

    private var richWeatherCity: String? = null

    /** The query actually sent to Brave's rich lookup. Bare names get the phrasing the intent
     *  detector reliably hints on ("bitcoin" → "bitcoin price", "tsla" → "tsla stock"); bare
     *  "weather" gets the city from the last known location, since Brave won't hint weather
     *  without a place. Blocking (geocoder) — call off the main thread. */
    private fun resolveBraveRichQuery(q: String): String? {
        val lower = q.lowercase(Locale.US)
        return when {
            lower in BraveSearchApi.CRYPTO_TERMS -> "$lower price"
            lower in BraveSearchApi.STOCK_TERMS || looksLikeTicker(q) -> "$lower stock"
            looksLikeLocalIntent(lower) -> q   // POI lookup: the locations block answers it
            BraveSearchApi.matchesLandmark(lower) -> q   // landmark: the infobox answers it
            lower == "weather" || lower == "forecast" -> {
                val city = richWeatherCity ?: AgenticLocation.lastKnown(this)?.let { loc ->
                    runCatching {
                        @Suppress("DEPRECATION")
                        android.location.Geocoder(this, Locale.getDefault())
                            .getFromLocation(loc.latitude, loc.longitude, 1)
                            ?.firstOrNull()?.locality
                    }.getOrNull()
                }?.also { richWeatherCity = it }
                city?.let { "weather $it" }
            }
            looksLikeRichIntent(q) -> q
            else -> null
        }
    }

    /** Debounced Google (Custom Search JSON) fallback rows. Brave is reserved for rich answers
     *  only — when no rich card exists for the query, these rows are the web results, and each
     *  tap goes straight to the target page: no search-engine page in between. */
    private fun scheduleBraveWebSearch() {
        webFallbackDebounce?.let { handler.removeCallbacks(it) }
        val q = query.trim()
        if (q.length < 3 || !GoogleSearchApi.isConfigured(prefs())) {
            if (webFallbackResults.isNotEmpty()) { webFallbackResults = emptyList(); webFallbackQuery = "" }
            return
        }
        if (q == webFallbackQuery) return
        val r = Runnable {
            webFallbackDebounce = null
            mediaUiScope.launch { fetchWebFallback(q) }
        }
        webFallbackDebounce = r
        handler.postDelayed(r, 600L)
    }

    private suspend fun fetchWebFallback(q: String) {
        val hits = withContext(Dispatchers.IO) {
            val key = prefs().getString(GoogleSearchApi.KEY_PREF, null)?.trim().orEmpty()
            val cx = prefs().getString(GoogleSearchApi.CX_PREF, null)?.trim().orEmpty()
            runCatching { GoogleSearchApi.search(q, key, cx, count = 5) }.getOrDefault(emptyList())
        }
        if (query.trim() != q) return   // query moved on
        webFallbackQuery = q
        webFallbackResults = hits.take(5).map { hit ->
            SearchResult(
                title = hit.title,
                subtitle = hit.display,
                accent = 0xFF4285F4.toInt(),   // Google blue
                kind = SearchKind.WEB,
                target = null,
                action = { openUrlDirectly(hit.link) },
                longAction = { startSafeIntent(Intent(Intent.ACTION_VIEW, Uri.parse(hit.link)), "No browser available") }
            )
        }
        refreshSearchResultsUi()
    }

    /** Debounced ESPN scores lookup. Populates [sportsCard] for the current query so the search
     *  surfaces can pin a live-score card on top ("miami heat", "nba scores", "world cup").
     *  ESPN's site API is free and unmetered, so this fires on any sports-shaped query. */
    private fun scheduleSportsSearch() {
        sportsDebounce?.let { handler.removeCallbacks(it) }
        val q = query.trim()
        if (q.length < 3 || !SportsApi.hasSportsIntent(q)) {
            if (sportsCard != null || sportsQuery.isNotEmpty()) { sportsCard = null; sportsQuery = "" }
            return
        }
        if (q == sportsQuery) return
        val r = Runnable {
            sportsDebounce = null
            mediaUiScope.launch {
                val card = withContext(Dispatchers.IO) {
                    runCatching { SportsApi.lookup(q) }.getOrNull()
                }
                if (query.trim() != q) return@launch   // query moved on
                sportsQuery = q
                sportsCard = card
                // Also refresh when the lookup came back empty: retiring a card changes the band as
                // much as gaining one, and the web rows it suppresses need to come back.
                refreshSearchResultsUi()
            }
        }
        sportsDebounce = r
        handler.postDelayed(r, 300L)
    }

    /** Does [q] look like it wants an instant answer (Brave rich vertical) rather than an app,
     *  contact, or web page? Deliberately conservative — a miss still spends two API requests. */
    private fun looksLikeRichIntent(q: String): Boolean {
        val lower = q.lowercase(Locale.US)
        if (lower.contains("weather") || lower.contains("forecast")) return true
        // Definitions are opt-in ("define:word") — the free dictionary answers these, so Brave
        // never needs to spend two requests on a word.
        if (lower.startsWith("define:") || lower.startsWith("define ") || lower.startsWith("meaning of ")) return false
        // "aapl stock", "bitcoin price", "eur to usd", "100 usd in eur"
        if (lower.endsWith(" stock") || lower.endsWith(" price") || lower.endsWith(" quote")) return true
        val words = lower.split(' ').filter { it.isNotBlank() }
        if (words.size in 3..5 && (words.contains("to") || words.contains("in")) &&
            words.first().any { it.isDigit() }) return true   // conversions: "3 miles in km"
        // arithmetic: at least one operator between digits ("12*8", "(3+4)^2")
        if (lower.any { it.isDigit() } && lower.any { it in "+*/^%=" } &&
            lower.all { it.isDigit() || it in "+-*/^%=(). " }) return true
        // sports: "lakers vs celtics"
        if (words.size >= 3 && words.contains("vs")) return true
        return false
    }

    /** Auto-download the ungated nomic embedder (84MB), enable semantic search, build the index.
     *  [onProgress] gets a status string; [onDone] fires with success. Runs off the main thread. */
    private fun downloadSemanticModel(onProgress: (String) -> Unit = {}, onDone: (Boolean) -> Unit = {}) {
        if (com.fran.teclas.llm.EmbedEngine.modelInstalled(this)) { onDone(true); return }
        onProgress("Starting…")
        mediaUiScope.launch {
            val poll = object : Runnable {
                override fun run() {
                    val e = com.fran.teclas.llm.EmbedEngine
                    if (e.downloading) {
                        val pct = (e.downloadedBytes * 100 / e.totalBytes).toInt()
                        onProgress("Downloading… $pct%")
                        handler.postDelayed(this, 400)
                    }
                }
            }
            handler.postDelayed(poll, 300)
            val ok = withContext(Dispatchers.IO) {
                runCatching { com.fran.teclas.llm.EmbedEngine.downloadModel(this@MainActivity) }.getOrDefault(false)
            }
            handler.removeCallbacks(poll)
            if (ok) {
                prefs().edit().putBoolean(SEMANTIC_SEARCH_PREF, true).apply()
                rebuildSemanticIndex()
            }
            onDone(ok)
        }
    }

    private fun playSpotifyTrackFromSearch(track: SpotifyTrack) {
        mediaUiScope.launch {
            val started = withContext(Dispatchers.IO) {
                runCatching { spotifyApi.playTrack(track.uri) }.getOrDefault(false)
            }
            if (started) {
                Toast.makeText(this@MainActivity, "Playing ${track.name}", Toast.LENGTH_SHORT).show()
                return@launch
            }
            val spotifyIntent = Intent(Intent.ACTION_VIEW, Uri.parse(track.uri)).apply {
                setPackage("com.spotify.music")
            }
            val opened = runCatching {
                startActivity(spotifyIntent)
                true
            }.getOrDefault(false)
            if (!opened) {
                val webUrl = if (track.id.startsWith("spotify:")) {
                    "https://open.spotify.com/search/${Uri.encode(track.name + " " + track.artist)}"
                } else {
                    "https://open.spotify.com/track/${Uri.encode(track.id)}"
                }
                startSafeIntent(Intent(Intent.ACTION_VIEW, Uri.parse(webUrl)), "Spotify can't play this track here")
            }
        }
    }

    private fun handleChatKey(label: String, pane: PaneTarget) {
        when (label) {
            "back" -> {
                if (autocorrectCore.undoOnBackspace()) { updateAutoCapState(); updateKeyLabels(); return }
                val pos = cursorPos
                if (pos != null && pos > 0) {
                    composeText = composeText.removeRange(pos - 1, pos)
                    cursorPos = pos - 1
                } else {
                    cursorPos = null
                    composeText = composeText.dropLast(1)
                }
                updateAutoCapState(); updateKeyLabels(); scheduleSpellCheck()
            }
            "space" -> {
                autocorrectCore.clearPending()
                if (maybeRunLauncherAiCommand()) return
                cursorPos?.let { pos ->
                    composeText = composeText.substring(0, pos) + " " + composeText.substring(pos)
                    cursorPos = pos + 1
                    suggestions = emptyList(); updateSuggestionBar()
                    updateAutoCapState(); updateKeyLabels()
                    renderPaneContent(pane); renderRibbon()
                    return
                }
                val now = System.currentTimeMillis()
                if (now - lastSpaceMs < 500 && composeText.isNotEmpty() && composeText.last() == ' ') {
                    composeText = composeText.dropLast(1) + ". "
                    shiftState = ShiftState.ONCE; updateKeyLabels()
                    suggestions = emptyList(); updateSuggestionBar()
                } else {
                    tryAutocorrect()
                    if (!composeText.endsWith(" ")) composeText += " "
                    suggestions = emptyList(); updateSuggestionBar()
                    updateAutoCapState(); updateKeyLabels()
                }
                lastSpaceMs = now
            }
            "period" -> {
                autocorrectCore.clearPending()
                cursorPos?.let { pos ->
                    composeText = composeText.substring(0, pos) + "." + composeText.substring(pos)
                    cursorPos = pos + 1
                    shiftState = ShiftState.ONCE; updateKeyLabels()
                    suggestions = emptyList(); updateSuggestionBar()
                    renderPaneContent(pane); renderRibbon()
                    return
                }
                tryAutocorrect()
                composeText = composeText.trimEnd() + "."
                shiftState = ShiftState.ONCE; updateKeyLabels()
                suggestions = emptyList(); updateSuggestionBar()
            }
            "123" -> { numberPadOpen = true; ensureContactsPermission(); render(); return }
            "abc" -> {
                if (symbolsOpen) { symbolsOpen = false; render(); return }
                numberPadOpen = false; render(); return
            }
            "teclas" -> {
                if (keyboardPlacement == KEYBOARD_PLACEMENT_WIDGET) setKeyboardPlacement(KEYBOARD_PLACEMENT_DOCKED)
                else {
                    keyboardSettingsOpen = false
                    setKeyboardPlacement(KEYBOARD_PLACEMENT_WIDGET)
                }
                return
            }
            "enter" -> postComposeBubble(pane)
            else -> {
                autocorrectCore.clearPending()
                val char = if (shiftState != ShiftState.OFF) label.uppercase(Locale.US) else label
                val pos = cursorPos
                if (pos != null) {
                    composeText = composeText.substring(0, pos) + char + composeText.substring(pos)
                    cursorPos = pos + 1
                } else {
                    composeText += char
                }
                if (shiftState == ShiftState.ONCE) { shiftState = ShiftState.OFF; updateKeyLabels() }
                scheduleSpellCheck()
                scheduleGeminiSuggestions()
            }
        }
        renderPaneContent(pane)
        renderRibbon()
    }

    private fun deleteWord() {
        val pane = openPane
        if (pane?.kind == PaneKind.CHAT) {
            composeText = WordBoundaryDeleter.deleteWord(composeText)
            updateAutoCapState(); updateKeyLabels()
            suggestions = emptyList(); updateSuggestionBar()
            renderPaneContent(pane); renderRibbon()
            return
        }
        if (pane?.kind == PaneKind.AI) {
            aiDraftText = WordBoundaryDeleter.deleteWord(aiDraftText)
            aiDraftActive = true
            suggestions = emptyList(); updateSuggestionBar()
            renderPaneContent(pane); renderRibbon()
            return
        }
        query = WordBoundaryDeleter.deleteWord(query)
        suggestions = emptyList(); updateSuggestionBar()
        renderRibbon()
    }

    // ── Letter shortcuts ─────────────────────────────────────────────────────

    private fun handleLetterLongPress(letter: String) {
        val stored = prefs().getString("letter_shortcut_$letter", null)
        if (stored != null) {
            // Special action shortcuts (not an app launch): "action:<name>".
            if (stored.startsWith("action:")) {
                if (stored == "action:uber_ride") promptUberDestination()
                return
            }
            val intent = packageManager.getLaunchIntentForPackage(stored)
            if (intent != null) { startActivity(intent); return }
            // Package gone — clear stale shortcut
            prefs().edit().remove("letter_shortcut_$letter").apply()
        }
        showLetterShortcutPicker(letter)
    }

    private fun showLetterShortcutPicker(letter: String) {
        val installed = apps.sortedBy { it.label }
        // Special actions surface above the app list so a key can hold a launcher action, not just
        // an app — e.g. an Uber "Where to?" ride prompt bound to a key.
        val specials = listOf("🚗  Uber ride — ask \"Where to?\"" to "action:uber_ride")
        val labels = (listOf("— Clear shortcut —") + specials.map { it.first } + installed.map { it.label }).toTypedArray()
        AlertDialog.Builder(this)
            .setTitle("Long-press \"${letter.uppercase(Locale.US)}\" opens...")
            .setItems(labels) { _, which ->
                val value = when {
                    which == 0 -> null
                    which <= specials.size -> specials[which - 1].second
                    else -> installed[which - 1 - specials.size].packageName
                }
                if (value == null) prefs().edit().remove("letter_shortcut_$letter").apply()
                else prefs().edit().putString("letter_shortcut_$letter", value).apply()
            }
            .show()
    }

    // Uber "Where to?" prompt — a key shortcut (or anywhere) can ask for a destination, then hand it
    // straight to Uber: pickup = the rider's GPS, dropoff = the typed place (context-resolved +
    // geocoded via launchUber). Enter in the field fires the ride.
    private fun promptUberDestination() {
        val input = android.widget.EditText(this).apply {
            hint = "e.g. Eiffel Tower, the airport, home"
            inputType = android.text.InputType.TYPE_CLASS_TEXT or android.text.InputType.TYPE_TEXT_FLAG_CAP_WORDS
            setSingleLine()
        }
        val wrap = FrameLayout(this).apply { setPadding(dp(22), dp(8), dp(22), 0); addView(input) }
        val dialog = AlertDialog.Builder(this)
            .setTitle("🚗  Uber — where to?")
            .setView(wrap)
            .setPositiveButton("Ride") { _, _ -> launchUber(input.text?.toString().orEmpty()) }
            .setNegativeButton("Cancel", null)
            .create()
        input.setOnEditorActionListener { _, _, _ ->
            dialog.dismiss(); launchUber(input.text?.toString().orEmpty()); true
        }
        dialog.setOnShowListener {
            input.requestFocus()
            dialog.window?.setSoftInputMode(WindowManager.LayoutParams.SOFT_INPUT_STATE_VISIBLE)
        }
        dialog.show()
    }

    // ── Pane / navigation ────────────────────────────────────────────────────

    private fun openHere(target: PaneTarget) {
        if (target.id == THEME_STUDIO_TARGET_ID) {
            themePaneHost.openThemeStudio()
            return
        }
        if (!target.id.startsWith("reply:")) replyingToKey = null
        closeCategoryFolder()
        libraryOpen = false
        libraryView?.let { contentFrame.removeView(it) }
        keyboardSettingsOpen = false; query = ""; composeText = ""
        shiftState = ShiftState.ONCE; suggestions = emptyList()
        updateKeyLabels(); updateSuggestionBar()
        openPane = target
        if (target.kind == PaneKind.SETTINGS) {
            render()
            return
        }
        if (keyboardPlacement == KEYBOARD_PLACEMENT_WIDGET && target.usesMediaDock()) {
            render()
            return
        }
        showPane(target, animate = true); renderRibbon(); refreshKeyboardDock()
        syncSystemBars()
        syncNowPlayingCardVisibility()
        refreshNowPlayingCard()
    }

    private fun openLibraryResult(target: PaneTarget) {
        closeCategoryFolder()
        libraryOpen = false
        libraryView?.let { contentFrame.removeView(it) }
        renderRibbon()
        syncNowPlayingCardVisibility()
        refreshNowPlayingCard()
        if (target.kind == PaneKind.MUSIC || target.packageName == null) openHere(target) else openExternal(target)
    }

    private fun showPane(target: PaneTarget, animate: Boolean) {
        paneView?.let { contentFrame.removeView(it) }
        paneView = pane(target).also { p ->
            contentFrame.addView(p, FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.MATCH_PARENT)
            if (animate) p.post { p.translationY = p.height.toFloat(); p.animate().translationY(0f).setDuration(340).start() }
        }
        if (target.kind == PaneKind.MUSIC) showMusicProgressInHintBar()
        else hideMusicProgressFromHintBar()
    }

    // ── Music progress bar in hint bar ────────────────────────────────────────

    private fun showMusicProgressInHintBar() {
        if (!::hintBar.isInitialized) return
        for (i in 0 until hintBar.childCount) hintBar.getChildAt(i).visibility = View.GONE

        val trackNameView = TextView(this).apply {
            textSize = 9.5f
            typeface = Typeface.create("sans-serif-medium", Typeface.NORMAL)
            letterSpacing = 0.04f
            setTextColor(0xFFCED2DA.toInt())
            maxLines = 1
            ellipsize = android.text.TextUtils.TruncateAt.END
            gravity = Gravity.CENTER_VERTICAL
            setPadding(dp(16), 0, dp(8), 0)
        }

        val timeText = TextView(this).apply {
            textSize = 8.5f
            typeface = Typeface.create("sans-serif", Typeface.NORMAL)
            setTextColor(0xFF6B7280.toInt())
            gravity = Gravity.CENTER_VERTICAL
            setPadding(0, 0, dp(14), 0)
            minWidth = dp(36)
        }

        // Scrubber bar — tappable/draggable, lives at the very bottom of the hintBar
        val scrubTrack = View(this).apply { setBackgroundColor(0xFF1E2229.toInt()) }
        val scrubFill = View(this).apply { setBackgroundColor(0xFF1ED760.toInt()) }
        val scrubContainer = FrameLayout(this).apply {
            addView(scrubTrack, FrameLayout.LayoutParams.MATCH_PARENT, dp(2))
            addView(scrubFill, FrameLayout.LayoutParams(0, dp(2)))
            setOnTouchListener { v, event ->
                val info = if (::mediaSessionSource.isInitialized) mediaSessionSource.nowPlaying.value else null
                val dur = info?.durationMs ?: 0L
                if (dur > 0 && (event.action == android.view.MotionEvent.ACTION_DOWN || event.action == android.view.MotionEvent.ACTION_MOVE)) {
                    val fraction = (event.x / v.width.toFloat()).coerceIn(0f, 1f)
                    mediaSessionSource.seekTo((dur * fraction).toLong())
                }
                true
            }
        }

        val row = LinearLayout(this).apply {
            orientation = LinearLayout.HORIZONTAL
            gravity = Gravity.CENTER_VERTICAL
            layoutParams = LinearLayout.LayoutParams(LinearLayout.LayoutParams.MATCH_PARENT, LinearLayout.LayoutParams.MATCH_PARENT)
        }
        row.addView(trackNameView, LinearLayout.LayoutParams(0, LinearLayout.LayoutParams.MATCH_PARENT, 1f))
        row.addView(timeText, LinearLayout.LayoutParams(LinearLayout.LayoutParams.WRAP_CONTENT, LinearLayout.LayoutParams.MATCH_PARENT))

        val overlay = FrameLayout(this).apply {
            layoutParams = LinearLayout.LayoutParams(LinearLayout.LayoutParams.MATCH_PARENT, LinearLayout.LayoutParams.MATCH_PARENT)
        }
        overlay.addView(row, FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.MATCH_PARENT)
        overlay.addView(scrubContainer, FrameLayout.LayoutParams(FrameLayout.LayoutParams.MATCH_PARENT, dp(2), Gravity.BOTTOM))

        hintBar.addView(overlay)
        musicProgressBar = overlay

        fun updateProgress() {
            if (!::mediaSessionSource.isInitialized) return
            val info = mediaSessionSource.nowPlaying.value ?: return
            val elapsed = android.os.SystemClock.elapsedRealtime() - info.lastUpdateElapsedMs
            val pos = if (info.isPlaying) (info.positionMs + elapsed).coerceAtMost(info.durationMs) else info.positionMs
            val dur = info.durationMs.takeIf { it > 0 } ?: return

            trackNameView.text = info.title

            val remaining = ((dur - pos) / 1000L).coerceAtLeast(0)
            val m = remaining / 60; val s = remaining % 60
            timeText.text = "-${m}:${s.toString().padStart(2, '0')}"

            val fraction = (pos.toFloat() / dur.toFloat()).coerceIn(0f, 1f)
            val accent = if (info.appIconColor != 0) info.appIconColor else 0xFF1ED760.toInt()
            scrubFill.setBackgroundColor(accent)
            scrubTrack.post {
                val totalW = scrubTrack.width
                if (totalW > 0) {
                    scrubFill.layoutParams = FrameLayout.LayoutParams((totalW * fraction).toInt(), dp(2))
                    scrubFill.requestLayout()
                }
            }
        }

        val handler = android.os.Handler(android.os.Looper.getMainLooper())
        val runnable = object : Runnable {
            override fun run() {
                if (musicProgressBar == null) return
                updateProgress()
                val playing = (if (::mediaSessionSource.isInitialized) mediaSessionSource.nowPlaying.value?.isPlaying else null) ?: false
                if (playing) handler.postDelayed(this, 1000)
                // when paused: don't reschedule — nowPlaying collect will restart us on resume
            }
        }
        musicProgressHandler = handler
        musicProgressRunnable = runnable
        handler.post(runnable)
    }

    private fun hideMusicProgressFromHintBar() {
        if (!::hintBar.isInitialized) return
        musicProgressHandler?.removeCallbacks(musicProgressRunnable ?: return)
        musicProgressHandler = null; musicProgressRunnable = null
        // Remove progress overlay
        musicProgressBar?.let { hintBar.removeView(it) }
        musicProgressBar = null
        // Restore original children visibility
        for (i in 0 until hintBar.childCount) hintBar.getChildAt(i).visibility = View.VISIBLE
    }

    private fun closePane() {
        val closing = paneView
        val closingPane = openPane
        val restoreWidgetKeyboard = keyboardPlacement == KEYBOARD_PLACEMENT_WIDGET && closingPane?.usesMediaDock() == true
        openPane = null; composeText = ""; aiDraftText = ""; aiDraftActive = false
        replyingToKey = null
        shiftState = ShiftState.OFF; suggestions = emptyList()
        if (closingPane?.kind == PaneKind.PHOTOS) zeissButtonView?.animateShutterOpen()
        if (closingPane?.kind == PaneKind.MUSIC) hideMusicProgressFromHintBar()
        updateKeyLabels(); updateSuggestionBar(); renderRibbon(); refreshKeyboardDock(); syncNowPlayingCardVisibility(); refreshNowPlayingCard()
        syncSystemBars()
        if (restoreWidgetKeyboard) {
            render()
            return
        }
        if (closingPane?.kind == PaneKind.SETTINGS) {
            render()
            return
        }
        if (closing == null) return
        closing.animate().translationY(closing.height.toFloat()).setDuration(220).withEndAction {
            contentFrame.removeView(closing); if (paneView === closing) paneView = null
        }.start()
    }

    private fun pane(target: PaneTarget): View {
        if (target.kind == PaneKind.AI) {
            return FrameLayout(this).apply {
                setBackgroundColor(Color.TRANSPARENT)
                tag = PANE_BODY_TAG
                addView(aiPane(target), FrameLayout.LayoutParams(FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.MATCH_PARENT))
            }
        }
        if (target.kind == PaneKind.MUSIC || target.kind == PaneKind.PHOTOS) {
            return FrameLayout(this).apply {
                setBackgroundColor(Panel)
                tag = PANE_BODY_TAG
                addView(paneBody(target), FrameLayout.LayoutParams(FrameLayout.LayoutParams.MATCH_PARENT, FrameLayout.LayoutParams.MATCH_PARENT))
                addView(paneBar(target), FrameLayout.LayoutParams(FrameLayout.LayoutParams.MATCH_PARENT, dp(54), Gravity.TOP))
            }
        }
        return LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL; setBackgroundColor(Panel); tag = PANE_BODY_TAG
            addView(paneBar(target), LinearLayout.LayoutParams.MATCH_PARENT, dp(48))
            addView(paneBody(target), LinearLayout.LayoutParams(LinearLayout.LayoutParams.MATCH_PARENT, 0, 1f))
            if (target.kind == PaneKind.CHAT) addView(composeBar(), LinearLayout.LayoutParams.MATCH_PARENT, dp(50))
        }
    }

    private fun paneBar(target: PaneTarget): View {
        val media = if (target.kind == PaneKind.MUSIC && ::mediaSessionSource.isInitialized) mediaSessionSource.nowPlaying.value else null
        val headerTitle = media?.sourceApp?.ifBlank { null } ?: target.name
        val headerAccent = media?.appIconColor ?: target.accent
        return LinearLayout(this).apply {
            orientation = LinearLayout.HORIZONTAL; gravity = Gravity.CENTER_VERTICAL
            setPadding(dp(14), 0, dp(10), 0)
            background = when (target.kind) {
                PaneKind.MUSIC -> musicHeaderGlassBg()
                PaneKind.PHOTOS -> zeissHeaderGlassBg()
                else -> frostedHeaderBg()
            }
            if (target.kind == PaneKind.MUSIC) {
                elevation = dp(10).toFloat()
                isClickable = true
                setOnClickListener {
                    haptic(this)
                    mediaSessionSource.openSourceApp()
                }
            } else if (target.kind == PaneKind.PHOTOS) {
                elevation = dp(10).toFloat()
            }
            val iconBitmap = media?.appIcon
            if (target.kind == PaneKind.MUSIC && iconBitmap != null) {
                addView(ImageView(context).apply {
                    setImageBitmap(iconBitmap)
                    scaleType = ImageView.ScaleType.CENTER_CROP
                    background = GradientDrawable().apply { setColor(0x3316181D); cornerRadius = dp(8).toFloat() }
                    setPadding(dp(2), dp(2), dp(2), dp(2))
                }, LinearLayout.LayoutParams(dp(28), dp(28)).apply { marginEnd = dp(10) })
            } else if (target.kind == PaneKind.PHOTOS) {
                addView(zeissHeaderBadge(), LinearLayout.LayoutParams(dp(26), dp(26)).apply { marginEnd = dp(10) })
            } else {
                addView(TextView(context).apply {
                    text = headerTitle.take(1).uppercase(Locale.US); textSize = 13f; gravity = Gravity.CENTER
                    typeface = Typeface.DEFAULT_BOLD; setTextColor(0xFF10110F.toInt())
                    background = GradientDrawable().apply { setColor(headerAccent); cornerRadius = dp(7).toFloat() }
                }, LinearLayout.LayoutParams(dp(26), dp(26)).apply { marginEnd = dp(10) })
            }
            addView(TextView(context).apply {
                text = headerTitle; textSize = 13f; typeface = Typeface.DEFAULT_BOLD
                letterSpacing = 0.03f; setTextColor(Ink)
            }, LinearLayout.LayoutParams(0, ViewGroup.LayoutParams.WRAP_CONTENT, 1f))
            when (target.kind) {
                PaneKind.MUSIC -> addView(View(context), LinearLayout.LayoutParams(dp(28), dp(28)))
                PaneKind.PHOTOS -> addView(View(context), LinearLayout.LayoutParams(dp(28), dp(28)))
                else -> {
                    addView(TextView(context).apply {
                        text = "X"; textSize = 14f; gravity = Gravity.CENTER; setTextColor(InkDim)
                        background = keyBackground(); isClickable = true
                        setOnClickListener { haptic(this); closePane() }
                    }, LinearLayout.LayoutParams(dp(28), dp(28)))
                }
            }
        }
    }

    private fun paneBody(target: PaneTarget): View {
        if (target.kind == PaneKind.MUSIC) return musicPane()
        if (target.kind == PaneKind.PHOTOS) return photosPane()
        if (target.kind == PaneKind.AI) return aiPane(target)
        if (target.id == AGENDA_TARGET_ID) return agendaPane()
        return ScrollView(this).apply {
            addView(LinearLayout(context).apply {
                orientation = LinearLayout.VERTICAL; setPadding(dp(16), dp(14), dp(16), dp(14))
                when (target.kind) {
                    PaneKind.CHAT -> chatLines(target).forEach { addView(bubble(it)) }
                    PaneKind.MAIL -> mailLines(target).forEach { addView(listRow(it.first, it.second)) }
                    PaneKind.MUSIC -> Unit
                    PaneKind.PHOTOS -> Unit
                    PaneKind.AI -> Unit
                    PaneKind.SETTINGS -> settingsPaneContent(this)
                    PaneKind.LIST -> {
                        addView(listRow("Inbox", "now"))
                        addView(listRow(target.preview.ifBlank { "Open ${target.name}" }, "item"))
                        addView(listRow("Open in real app from long press", "external"))
                    }
                }
            })
        }
    }

    private fun aiPane(target: PaneTarget): View {
        return ComposeView(this).apply {
            setBackgroundColor(Color.TRANSPARENT)
            setContent {
                val state = aiAnswersById[target.id] ?: AiAnswerState(target.preview, "Thinking...", true)
                val configured = geminiConfigured()
                val displayedQuery = if (aiDraftActive || aiDraftText.isNotBlank()) aiDraftText else state.prompt
                val answer = if (configured) {
                    state.answer
                } else {
                    "Add a **Gemini API key** in Teclas Settings to ask questions without leaving the launcher."
                }
                TeclasAiQueryFlow(
                    query = displayedQuery,
                    answer = answer,
                    glassEffects = glassEffectsEnabled(),
                    loading = configured && state.loading,
                    askedActive = aiDraftActive || aiDraftText.isNotBlank(),
                    onClose = {
                        haptic(this@apply)
                        closePane()
                    },
                    onAskedClick = {
                        haptic(this@apply)
                        aiDraftText = ""
                        aiDraftActive = true
                        renderPaneContent(target)
                        renderRibbon()
                    },
                    onJoin = { url ->
                        haptic(this@apply)
                        startSafeIntent(Intent(Intent.ACTION_VIEW, Uri.parse(url)), "Meeting link isn't available")
                    },
                    onOpenCalendar = { event ->
                        haptic(this@apply)
                        openCalendarEventOrRequest(event)
                    }
                )
            }
        }
    }

    private fun photosPane(): View {
        return ComposeView(this).apply {
            setBackgroundColor(Panel)
            setContent {
                LauncherPhotos(
                    hasPermission = hasPhotoPermission(),
                    selectedBucket = selectedPhotoBucket(),
                    selectedPhotoId = selectedPhotoId(),
                    favoriteIds = favoritePhotoIds(),
                    brandStamp = photoStampLabel(),
                    onPhotoSelected = { id -> persistSelectedPhoto(id) },
                    onOpenExternalPhoto = { uri -> openExternalPhoto(uri) },
                    onToggleFavorite = { photo -> toggleFavoritePhoto(photo.id) },
                    onDeletePhoto = { photo -> requestTrashPhoto(photo) },
                    onRequestPermission = { photosPermissionLauncher.launch(photoPermissionName()) }
                )
            }
        }
    }

    private fun openExternalPhoto(uri: Uri) {
        val intent = Intent(Intent.ACTION_VIEW).apply {
            setDataAndType(uri, "image/*")
            addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
        }
        runCatching { startActivity(intent) }
            .onFailure { Toast.makeText(this, "No photo viewer found.", Toast.LENGTH_SHORT).show() }
    }

    private fun musicPane(): View {
        return ComposeView(this).apply {
            setBackgroundColor(Panel)
            setContent {
                val media by mediaSessionSource.nowPlaying.collectAsState()
                MusicPlayer(
                    media = media,
                    initialTheme = musicTheme(),
                    onThemeChanged = { theme ->
                        prefs().edit().putString(MUSIC_THEME_PREF, theme).apply()
                        refreshKeyboardDock()
                    },
                    onOpenSource = {
                        haptic(this@apply)
                        mediaSessionSource.openSourceApp()
                    },
                    onTogglePlayPause = {
                        haptic(this@apply)
                        mediaSessionSource.togglePlayPause()
                    },
                    onPrevious = {
                        haptic(this@apply)
                        mediaSessionSource.skipToPrevious()
                    },
                    onNext = {
                        haptic(this@apply)
                        mediaSessionSource.skipToNext()
                    },
                    onSeekTo = { positionMs ->
                        haptic(this@apply)
                        mediaSessionSource.seekTo(positionMs)
                    }
                )
            }
        }
    }

