            background = Neu.drawable(activeNeuTokens, dp(13).toFloat(), NeuLevel.PRESSED_SM)
            isClickable = true
            setOnClickListener { haptic(this); onClick() }
            addView(ImageView(context).apply {
                setImageDrawable(
                    runCatching { provider.loadPreviewImage(this@MainActivity, resources.displayMetrics.densityDpi) }.getOrNull()
                        ?: runCatching { packageManager.getApplicationIcon(provider.provider.packageName) }.getOrNull()
                )
                scaleType = ImageView.ScaleType.CENTER_CROP
            }, LinearLayout.LayoutParams(dp(28), dp(28)))
            addView(TextView(context).apply {
                text = label
                textSize = 13f
                typeface = Typeface.DEFAULT_BOLD
                includeFontPadding = false
                maxLines = 1
                ellipsize = android.text.TextUtils.TruncateAt.END
                setTextColor(activeNeuTokens.ink)
                setPadding(dp(9), 0, 0, 0)
            }, LinearLayout.LayoutParams(0, ViewGroup.LayoutParams.WRAP_CONTENT, 1f))
        }
    }

    private fun addDockActionRows(menu: LinearLayout, popup: PopupWindow, anchor: View, target: PaneTarget) {
        val divider = View(this).apply { setBackgroundColor(adjustAlpha(activeNeuTokens.inkFaint, 0.18f)) }
        menu.addView(divider, LinearLayout.LayoutParams(LinearLayout.LayoutParams.MATCH_PARENT, dp(1)).apply {
            topMargin = dp(8)
            bottomMargin = dp(4)
        })
        val canOpenHere = target.kind != PaneKind.LIST || target.packageName == null
        menu.addView(menuItem("Open here", canOpenHere) { popup.dismiss(); openHere(target) })
        menu.addView(menuItem("Open app", target.packageName != null) { popup.dismiss(); openExternal(target) })
        if (target.kind == PaneKind.MUSIC) {
            menu.addView(menuItem("Change icon", true) {
                popup.dismiss()
                showIconMenu(anchor, musicLibraryApp())
            })
        }
        dockPresenceKey(target)?.takeIf { target.packageName == null }?.let {
            val onHome = isDockTargetOnHome(target)
            menu.addView(menuItem(if (onHome) "Remove from dock" else "Add to dock", true) {
                setDockTargetHomePresence(target, !onHome)
                popup.dismiss()
            })
        }
        target.packageName?.let { packageName ->
            val onHome = isOnHome(packageName)
            menu.addView(menuItem(if (onHome) "Remove from dock" else "Add to dock", true) {
                setHomePresence(packageName, !onHome)
                popup.dismiss()
            })
            apps.firstOrNull { it.packageName == packageName }?.let { app ->
                menu.addView(menuItem("Change icon", true) {
                    popup.dismiss()
                    showIconMenu(anchor, app.toLibraryApp())
                })
            }
        }
    }

    private fun showOpenMenu(anchor: View, target: PaneTarget) {
        val menu = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL; setPadding(dp(6), dp(6), dp(6), dp(6))
            background = GradientDrawable().apply { setColor(Panel2); cornerRadius = dp(8).toFloat(); setStroke(dp(1), Line) }
        }
        val popupWidth = dp(204)
        val popup = PopupWindow(menu, popupWidth, ViewGroup.LayoutParams.WRAP_CONTENT, true).apply {
            isOutsideTouchable = true
            setBackgroundDrawable(ColorDrawable(Color.TRANSPARENT))
        }
        val canOpenHere = target.kind != PaneKind.LIST || target.packageName == null
        menu.addView(menuItem("Open here", canOpenHere) { popup.dismiss(); openHere(target) })
        menu.addView(menuItem("Open app", target.packageName != null) { popup.dismiss(); openExternal(target) })
        if (target.kind == PaneKind.MUSIC) {
            menu.addView(menuItem("Change icon", true) {
                popup.dismiss()
                showIconMenu(anchor, musicLibraryApp())
            })
        }
        dockPresenceKey(target)?.takeIf { target.packageName == null }?.let {
            val onHome = isDockTargetOnHome(target)
            menu.addView(menuItem(if (onHome) "Remove from dock" else "Add to dock", true) {
                setDockTargetHomePresence(target, !onHome)
                popup.dismiss()
            })
        }
        target.packageName?.let { packageName ->
            val onHome = isOnHome(packageName)
            menu.addView(menuItem(if (onHome) "Remove from dock" else "Add to dock", true) {
                setHomePresence(packageName, !onHome)
                popup.dismiss()
            })
            apps.firstOrNull { it.packageName == packageName }?.let { app ->
                menu.addView(menuItem("Change icon", true) {
                    popup.dismiss()
                    showIconMenu(anchor, app.toLibraryApp())
                })
            }
        }
        showSmartDockPopup(anchor, popup, menu, popupWidth)
    }

    internal fun menuItem(label: String, enabled: Boolean, onClick: () -> Unit): View {
        return TextView(this).apply {
            text = label; textSize = 13f; gravity = Gravity.CENTER_VERTICAL
            setPadding(dp(10), dp(9), dp(10), dp(9))
            setTextColor(if (enabled) Ink else InkDim); isEnabled = enabled; isClickable = enabled
            setOnClickListener { haptic(this); onClick() }
        }
    }

    private fun showGoColorMenu(anchor: View) {
        showKeyColorMenu(anchor, goKeyColor) { color ->
            applyGoKeyColor(color, refreshSettings = false)
        }
    }

    private fun showKeyColorMenu(anchor: View, selectedColor: Int, onSelect: (Int) -> Unit) {
        val menu = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL; setPadding(dp(6), dp(6), dp(6), dp(6))
            background = GradientDrawable().apply { setColor(Panel2); cornerRadius = dp(8).toFloat(); setStroke(dp(1), Line) }
        }
        val popup = PopupWindow(menu, dp(152), ViewGroup.LayoutParams.WRAP_CONTENT, true).apply { isOutsideTouchable = true }
        GO_COLORS.forEach { option ->
            menu.addView(TextView(this).apply {
                text = option.name; textSize = 12f; typeface = Typeface.DEFAULT_BOLD; gravity = Gravity.CENTER_VERTICAL
                setTextColor(option.color); setPadding(dp(10), dp(9), dp(10), dp(9))
                background = if (selectedColor == option.color) highlight(option.color) else null
                isClickable = true
                setOnClickListener { haptic(this); onSelect(option.color); popup.dismiss() }
            })
        }
        popup.showAsDropDown(anchor, -dp(96), -dp(180))
    }

    // ── App loading ──────────────────────────────────────────────────────────

    private fun openExternal(target: PaneTarget): Boolean {
        target.deepLinkUri?.takeIf { it.startsWith("tel:") }?.let {
            startActivity(Intent(Intent.ACTION_DIAL, Uri.parse(it))); return true
        }
        val packageName = target.packageName
        if (packageName == null) { openHere(target); return true }
        try {
            if (target.deepLinkUri != null && isInstalled(packageName)) {
                return launchExternalIntent(Intent(Intent.ACTION_VIEW, Uri.parse(target.deepLinkUri)).setPackage(packageName), packageName)
            }
            val launchIntent = packageManager.getLaunchIntentForPackage(packageName)
            if (launchIntent != null) {
                return launchExternalIntent(launchIntent, packageName)
            }
            startActivity(Intent(Intent.ACTION_VIEW, Uri.parse("market://details?id=$packageName")))
            return true
        } catch (e: ActivityNotFoundException) {
            Toast.makeText(this, "${target.name} isn't available here", Toast.LENGTH_SHORT).show()
        }
        return false
    }

    private fun launchExternalIntent(intent: Intent, packageName: String): Boolean {
        if (keyboardPlacement == KEYBOARD_PLACEMENT_DOCKED) {
            if (!prepareDockedExternalMode()) return false
            val options = if (VivoDockedExperiment.isEnabled(this)) null else dockedExternalActivityOptions()
            if (options != null) {
                // Freeform launch bounds are honored only for a fresh root activity of a new task,
                // so clear any existing task for this app that would otherwise reopen fullscreen.
                intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK)
                runCatching {
                    startActivity(intent, options)
                }
                    .onFailure {
                        intent.addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP)
                        startActivity(intent)
                    }
            } else {
                intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
                startActivity(intent)
            }
            finishDockedExternalLaunch(packageName)
        } else {
            VivoDockedExperiment.clearViewportTruncation(this)
            startActivity(intent)
        }
        recordAppLaunch(packageName)
        return true
    }

    private fun finishDockedExternalLaunch(packageName: String) {
        DockedFreeform.externalAppInFront = true
        syncDockedSearchStatusBar()   // opaque status-bar strip so wallpaper doesn't bleed above the app
        requestDockedFreeformRepin(packageName)
    }

    private fun requestDockedFreeformRepin(packageName: String) {
        if (keyboardPlacement != KEYBOARD_PLACEMENT_DOCKED || packageName == this.packageName) return
        refreshDockedExternalKeyboardTop()
        sendBroadcast(Intent(InputInjectionService.ACTION_REPIN_FREEFORM).apply {
            setPackage(this@MainActivity.packageName)
        })
        if (!DockedFreeform.isFeatureEnabled(this) || !ShizukuPinner.isReady()) return
        listOf(240L, 900L).forEach { delayMs ->
            handler.postDelayed({
                val bounds = DockedFreeform.pinBounds(this@MainActivity)
                Thread({
                    ShizukuPinner.pin(packageName, bounds)
                }, "docked-freeform-repin").start()
            }, delayMs)
        }
    }

    private fun prepareDockedExternalMode(): Boolean {
        if (keyboardPlacement != KEYBOARD_PLACEMENT_DOCKED) return true
        refreshDockedExternalKeyboardTop()
        if (VivoDockedExperiment.isEnabled(this)) {
            VivoDockedExperiment.applyViewportTruncation(this)
            if (!Settings.canDrawOverlays(this)) {
                Toast.makeText(this, "Allow Teclas overlay so the docked keyboard can stay visible.", Toast.LENGTH_LONG).show()
                runCatching { startActivity(DockedKeyboardService.overlaySettingsIntent(this)) }
                return false
            }
            if (!isTeclasAccessibilityEnabled()) {
                Toast.makeText(this, "Enable Teclas Accessibility so the docked keyboard can type into apps.", Toast.LENGTH_LONG).show()
                runCatching { startActivity(Intent(Settings.ACTION_ACCESSIBILITY_SETTINGS)) }
                return false
            }
            startService(Intent(this, DockedKeyboardService::class.java))
        } else {
            stopService(Intent(this, DockedKeyboardService::class.java))
        }
        if (!isTeclasImeEnabled()) {
            Toast.makeText(this, "Enable Teclas Keyboard, then select it for docked typing.", Toast.LENGTH_LONG).show()
            runCatching { startActivity(Intent(Settings.ACTION_INPUT_METHOD_SETTINGS)) }
            return false
        }
        if (!isTeclasImeSelected()) {
            Toast.makeText(this, "Select Teclas Keyboard for docked mode.", Toast.LENGTH_LONG).show()
            getSystemService(android.view.inputmethod.InputMethodManager::class.java)?.showInputMethodPicker()
            return false
        }
        return true
    }

    private fun requestDockedSplitFallbackIfNeeded() {
        if (keyboardPlacement != KEYBOARD_PLACEMENT_DOCKED || dockedFreeformLikelyEnabled()) return
        handler.postDelayed({
            sendBroadcast(Intent(InputInjectionService.ACTION_TOGGLE_SPLIT_SCREEN).apply {
                setPackage(this@MainActivity.packageName)
            })
        }, 650L)
    }

    private fun dockedFreeformLikelyEnabled(): Boolean {
        val freeform = Settings.Global.getInt(contentResolver, "enable_freeform_support", 0) == 1
        val resizable = Settings.Global.getInt(contentResolver, "force_resizable_activities", 0) == 1
        return freeform && resizable
    }

    private fun isTeclasAccessibilityEnabled(): Boolean {
        val enabled = Settings.Secure.getString(contentResolver, Settings.Secure.ENABLED_ACCESSIBILITY_SERVICES).orEmpty()
        val mine = ComponentName(this, InputInjectionService::class.java).flattenToString()
        return enabled.split(':').any { it.equals(mine, ignoreCase = true) }
    }

    private fun isTeclasImeEnabled(): Boolean {
        val component = ComponentName(this, TeclasImeService::class.java)
        return getSystemService(android.view.inputmethod.InputMethodManager::class.java)
            ?.enabledInputMethodList
            ?.any { info ->
                info.packageName == component.packageName &&
                    info.serviceName == component.className
            } == true
    }

    private fun isTeclasImeSelected(): Boolean {
        val selected = runCatching {
            Settings.Secure.getString(contentResolver, Settings.Secure.DEFAULT_INPUT_METHOD).orEmpty()
        }.getOrDefault("")
        return selected.isBlank() || selected.matchesTeclasImeComponent()
    }

    private fun String.matchesTeclasImeComponent(): Boolean {
        val component = ComponentName(this@MainActivity, TeclasImeService::class.java)
        return equals(component.flattenToString(), ignoreCase = true) ||
            equals(component.flattenToShortString(), ignoreCase = true)
    }

    private fun dockedExternalActivityOptions(): android.os.Bundle? {
        if (keyboardPlacement != KEYBOARD_PLACEMENT_DOCKED) return null
        // Reserve the WHOLE docked keyboard band (search field + suggestion strip + keys) so the app
        // never covers the search bar, which must always show. Two sources, take whichever reserves
        // more: the measured on-screen top of the dock, and its computed height (deterministic —
        // works even before the view is laid out; the old height formula under-reserved and let the
        // app bottom fall over the search bar). Minus a small margin for clear separation.
        val keyboardTopPx = refreshDockedExternalKeyboardTop()
        // Returns an options Bundle only when the docked "apps in top region" feature is on and
        // freeform is armed; otherwise null → normal fullscreen launch.
        return DockedFreeform.activityOptions(this, keyboardTopPx)
    }

    private fun refreshDockedExternalKeyboardTop(): Int? {
        val screenH = resources.displayMetrics.heightPixels
        val measured = if (::keyboardDockView.isInitialized) {
            val loc = IntArray(2)
            keyboardDockView.getLocationOnScreen(loc)
            loc[1].takeIf { it > 0 && keyboardDockView.height > 0 }
        } else null
        val computed = (screenH - activeRootDockHeight() - launcherDockedKeyboardBottomLift()).takeIf { it in 1 until screenH }
        val keyboardTopPx = DockedFreeform.resolveKeyboardTop(this, measured, computed)
        // Share the top with the accessibility service so it can re-pin via Shizuku on window changes.
        keyboardTopPx?.let { DockedFreeform.lastKeyboardTopPx = it }
        return keyboardTopPx
    }

    // ---- Docked keyboard → foreground app typing (via the accessibility injector) ----

    private fun keysRouteToForegroundApp(): Boolean =
        DockedFreeform.externalAppInFront &&
            keyboardPlacement == KEYBOARD_PLACEMENT_DOCKED &&
            (DockedFreeform.isActive(this) || (DockedFreeform.isFeatureEnabled(this) && ShizukuPinner.isReady())) &&
            isTeclasAccessibilityEnabled()

    /**
     * Send one keystroke to the foreground app's focused field. Returns true when consumed (so the
     * launcher doesn't also handle it). "teclas" switches back to launcher search; "123"/"abc" fall
     * through so the deck can still change number/symbol modes.
     */
    private fun routeKeyToForegroundApp(label: String): Boolean {
        when (label) {
            "123", "abc" -> return false
            "teclas" -> { bringLauncherToFront(); return true }
            "back" -> {
                if (undoDockedForegroundAutocorrect()) return true   // backspace right after a correction = revert it
                dockedFgUndo = null
                mirrorDockedForegroundBackspace()
                injectToForegroundApp(InputInjectionService.KEY_BACKSPACE)
            }
            "space" -> {
                applyDockedForegroundAutocorrect()
                mirrorDockedForegroundInsert(" ")
                injectToForegroundApp(" ")
            }
            "period" -> {
                applyDockedForegroundAutocorrect()
                mirrorDockedForegroundInsert(".")
                injectToForegroundApp(".")
            }
            "enter" -> {
                dockedFgUndo = null
                injectToForegroundApp(InputInjectionService.KEY_ENTER)
                clearDockedForegroundDraft(localOnly = true)
            }
            else -> {
                dockedFgUndo = null
                val char = if (shiftState != ShiftState.OFF) label.uppercase(Locale.US) else label
                if (shiftState == ShiftState.ONCE) { shiftState = ShiftState.OFF; updateKeyLabels() }
                mirrorDockedForegroundInsert(char)
                injectToForegroundApp(char)
            }
        }
        return true
    }

    // ── Docked-foreground autocorrect: same AutocorrectCore decision as the launcher's own fields,
    //    applied to the third-party app's field via one atomic guarded tail-replace (no lag: the
    //    injector already owns the field text; a stale field makes the replace a silent no-op). ──
    private var dockedFgUndo: Pair<String, String>? = null   // typed -> corrected (armed until next key)

    private fun dockedForegroundCurrentWord(): String =
        dockedForegroundDraft.takeLastWhile { it.isLetter() }.toString()

    private fun applyDockedForegroundAutocorrect() {
        dockedFgUndo = null
        val word = dockedForegroundCurrentWord()
        if (word.length < 2 || word.length > 24) return
        val before = dockedForegroundDraft.dropLast(word.length).toString()
        val prev = Regex("[A-Za-z]+").findAll(before).lastOrNull()?.value.orEmpty()
        val corrected = autocorrectCore.computeCorrection(word, ngramRepo.cachedNextWords(prev), prev) ?: return
        if (corrected.equals(word, ignoreCase = true)) return
        val cased = if (word.first().isUpperCase()) corrected.replaceFirstChar { it.uppercase(Locale.US) } else corrected
        injectReplaceTailInForegroundApp(word, cased)
        dockedForegroundDraft.setLength(dockedForegroundDraft.length - word.length)
        dockedForegroundDraft.append(cased)
        dockedFgUndo = word to cased
        updateDockedForegroundChirpStrip()
    }

    /** Backspace immediately after an auto-correction restores the typed word (and remembers the
     *  rejection so the same "fix" is never forced again). Returns true when the key is consumed. */
    private fun undoDockedForegroundAutocorrect(): Boolean {
        val (typed, cased) = dockedFgUndo ?: return false
        dockedFgUndo = null
        val tail = "$cased "
        if (!dockedForegroundDraft.endsWith(tail)) return false
        val restore = "$typed "
        injectReplaceTailInForegroundApp(tail, restore)
        dockedForegroundDraft.setLength(dockedForegroundDraft.length - tail.length)
        dockedForegroundDraft.append(restore)
        rejectedStore.add(typed.lowercase(Locale.US), cased.lowercase(Locale.US))
        updateDockedForegroundChirpStrip()
        return true
    }

    private fun injectReplaceTailInForegroundApp(expect: String, with: String) {
        sendBroadcast(Intent(InputInjectionService.ACTION_REPLACE_TAIL).apply {
            setPackage(packageName)
            putExtra(InputInjectionService.EXTRA_EXPECT, expect)
            putExtra(InputInjectionService.EXTRA_WITH, with)
        })
    }

    private fun mirrorDockedForegroundInsert(text: String) {
        if (!dockedForegroundChirpActive()) return
        dockedForegroundDraft.append(text)
        pendingLauncherCommand = null
        pendingLauncherActions = emptyList()
        pendingLauncherStarters = emptyList()
        pendingLauncherResult = null
        launcherAgenticStatus = null
        updateDockedForegroundChirpStrip()
    }

    private fun mirrorDockedForegroundBackspace() {
        if (!dockedForegroundChirpActive()) return
        if (dockedForegroundDraft.isNotEmpty()) dockedForegroundDraft.deleteCharAt(dockedForegroundDraft.length - 1)
        pendingLauncherCommand = null
        pendingLauncherActions = emptyList()
        pendingLauncherStarters = emptyList()
        pendingLauncherResult = null
        launcherAgenticStatus = null
        updateDockedForegroundChirpStrip()
    }

    private fun insertDockedForegroundText(text: String) {
        if (text.isEmpty()) return
        text.forEach { ch ->
            val payload = if (ch == '\n') InputInjectionService.KEY_ENTER else ch.toString()
            injectToForegroundApp(payload)
            if (ch != '\n') dockedForegroundDraft.append(ch) else dockedForegroundDraft.append('\n')
        }
        updateDockedForegroundChirpStrip()
    }

    private fun clearDockedForegroundDraft(localOnly: Boolean = false) {
        if (!localOnly) repeat(dockedForegroundDraft.length) { injectToForegroundApp(InputInjectionService.KEY_BACKSPACE) }
        dockedForegroundDraft.clear()
        pendingLauncherCommand = null
        pendingLauncherActions = emptyList()
        pendingLauncherStarters = emptyList()
        pendingLauncherResult = null
        launcherAgenticStatus = null
        updateDockedForegroundChirpStrip()
    }

    private fun replaceDockedForegroundDraft(text: String) {
        clearDockedForegroundDraft()
        insertDockedForegroundText(text)
    }

    private fun injectToForegroundApp(payload: String) {
        // Type straight into the foreground app's focused field via the accessibility injector — the
        // launcher's own keyboard, no IME handoff. This is the fast path and, crucially, it works
        // while the launcher deck is the visible keyboard: routing through the IME dropped keys and
        // felt slow because the IME has no live InputConnection unless it is the on-screen keyboard.
        sendBroadcast(Intent(InputInjectionService.ACTION_INJECT_KEY).apply {
            setPackage(packageName)
            putExtra(InputInjectionService.EXTRA_CHAR, payload)
        })
    }

    /** Bring the launcher back to the front so typing targets launcher search again. */
    private fun bringLauncherToFront() {
        DockedFreeform.externalAppInFront = false
        runCatching {
            startActivity(Intent(this, MainActivity::class.java).apply {
                addFlags(Intent.FLAG_ACTIVITY_REORDER_TO_FRONT or Intent.FLAG_ACTIVITY_SINGLE_TOP)
            })
        }
    }

    // ---- Docked "apps in top region" (freeform) toggle + arming flow ----

    private fun toggleDockedTopRegion() {
        haptic(window.decorView)
        val turningOn = !DockedFreeform.isFeatureEnabled(this)
        DockedFreeform.setFeatureEnabled(this, turningOn)
        if (turningOn) {
            // Arming (the freeform globals) is the real enabler and the only reliable signal —
            // some OEMs support freeform without advertising the system feature. Needs the one-time
            // WRITE_SECURE_SETTINGS grant first; if that's missing, walk the user through it.
            when {
                !DockedFreeform.hasWriteSecureSettings(this) ->
                    showDockedTopRegionSetup()
                DockedFreeform.arm(this) ->
                    Toast.makeText(this, "Top-region mode on. If apps still open fullscreen, reboot once.", Toast.LENGTH_LONG).show()
                else ->
                    showDockedTopRegionSetup()
            }
        } else {
            DockedFreeform.disarm(this)
        }
        renderPaneContent(teclasSettingsTarget())
    }

    private fun dockedTopRegionStatusLabel(): String = when {
        !DockedFreeform.hasWriteSecureSettings(this) -> "NEEDS ADB GRANT →"
        !DockedFreeform.isArmed(this) -> "TAP TO ARM →"
        else -> "READY ✓"
    }

    private fun showDockedTopRegionSetup() {
        val cmd = DockedFreeform.adbGrantCommand(this)
        val hasPerm = DockedFreeform.hasWriteSecureSettings(this)
        val armed = DockedFreeform.isArmed(this)
        val body = buildString {
            append("Opens every app in the top region while the keyboard is docked.\n\n")
            when {
                !hasPerm -> {
                    append("One-time setup — run this from a computer with the phone connected:\n\n$cmd\n\n")
                    append("Then reopen this dialog and tap Re-check.")
                }
                !armed -> append("Permission granted. Tap Arm now to enable freeform windows.")
                else -> append("Ready. Apps you launch from Teclas open in the top region above the docked keyboard. If any still open fullscreen, reboot once.")
            }
        }
        val builder = AlertDialog.Builder(this)
            .setTitle("Apps in top region")
            .setMessage(body)
            .setNegativeButton("Close", null)
        if (!hasPerm) {
            builder.setPositiveButton("Copy command") { _, _ ->
                val cm = getSystemService(Context.CLIPBOARD_SERVICE) as? android.content.ClipboardManager
                cm?.setPrimaryClip(android.content.ClipData.newPlainText("adb", cmd))
                Toast.makeText(this, "Command copied", Toast.LENGTH_SHORT).show()
            }
            builder.setNeutralButton("Re-check") { _, _ ->
                if (DockedFreeform.hasWriteSecureSettings(this)) {
                    DockedFreeform.arm(this)
                    Toast.makeText(this, "Top-region mode armed", Toast.LENGTH_LONG).show()
                } else {
                    Toast.makeText(this, "Permission not granted yet", Toast.LENGTH_SHORT).show()
                }
                renderPaneContent(teclasSettingsTarget())
            }
        } else if (!armed) {
            builder.setPositiveButton("Arm now") { _, _ ->
                DockedFreeform.arm(this)
                renderPaneContent(teclasSettingsTarget())
            }
        }
        builder.show()
    }

    private fun shizukuStatusLabel(): String = when {
        !ShizukuPinner.isRunning() -> "NOT RUNNING →"
        !ShizukuPinner.hasPermission() -> "GRANT →"
        else -> "ON ✓"
    }

    private fun onShizukuRowTapped() {
        when {
            !ShizukuPinner.isRunning() -> AlertDialog.Builder(this)
                .setTitle("Pin apps with Shizuku")
                .setMessage(
                    "Holds apps in the top region across their own screens, and works on phones that block freeform.\n\n" +
                        "1. Install Shizuku from the Play Store.\n" +
                        "2. Start it (Wireless debugging, or via adb).\n" +
                        "3. Reopen this row and tap Grant."
                )
                .setPositiveButton("OK", null)
                .show()
            !ShizukuPinner.hasPermission() -> ShizukuPinner.requestPermission { granted ->
                runOnUiThread {
                    Toast.makeText(
                        this,
                        if (granted) "Shizuku granted — apps will stay pinned to the top region" else "Shizuku permission denied",
                        Toast.LENGTH_SHORT
                    ).show()
                    renderPaneContent(teclasSettingsTarget())
                }
            }
            else -> Toast.makeText(this, "Shizuku active — apps pinned to the top region", Toast.LENGTH_SHORT).show()
        }
    }

    private fun isInstalled(packageName: String) = packageManager.getLaunchIntentForPackage(packageName) != null

    private fun recordAppLaunch(packageName: String) {
        val counts = JSONObject(prefs().getString(APP_USAGE_PREF, "{}") ?: "{}")
        val nextCount = counts.optInt(packageName, 0) + 1
        counts.put(packageName, nextCount)
        val launches = JSONObject(prefs().getString(APP_LAST_LAUNCH_PREF, "{}") ?: "{}")
        launches.put(packageName, System.currentTimeMillis())
        prefs().edit()
            .putString(APP_USAGE_PREF, counts.toString())
            .putString(APP_LAST_LAUNCH_PREF, launches.toString())
            .apply()
        MostUsedAppsWidget.refreshAll(this)
        val source = pendingLaunchSource
        pendingLaunchSource = LaunchSource.OTHER
        mediaUiScope.launch(Dispatchers.Default) {
            runCatching {
                Predictor.recordLaunch(this@MainActivity, packageName, source, currentPredictSnapshot())
            }
            refreshPredictContext(rerender = true)
        }
        // Both library modes depend on launch data now: bento sorts categories by usage,
        // and the grid leads with the predicted row — leaving grid mode out kept the
        // predictions frozen at whatever the first render saw.
        libraryViewDirty = true
        libraryContentReady = false
        // Clear the typed search after launching — returning to the launcher shouldn't leave the
        // last query sitting there for the user to delete.
        if (libraryOpen) {
            closeLibrary()
        } else if (query.isNotEmpty()) {
            query = ""
            cursorPos = null
            suggestions = emptyList()
            renderRibbon()
        }
        renderFavoritesDock()
    }

    /** Fresh context snapshot; call off the main thread (calendar/location on cache miss). */
    private fun currentPredictSnapshot(): ContextSnapshot {
        val playing = if (::mediaSessionSource.isInitialized) {
            mediaSessionSource.nowPlaying.value?.isPlaying == true
        } else false
        return Predictor.snapshotNow(this, mediaPlaying = playing)
    }

    /** Recompute the prediction context off-main; optionally re-render dock + Space icon. */
    private fun refreshPredictContext(rerender: Boolean = false) {
        mediaUiScope.launch(Dispatchers.Default) {
            val snap = runCatching { currentPredictSnapshot() }.getOrNull() ?: return@launch
            // Piggyback the throttled place-inference pass (home/work/airport suggestions).
            runCatching { com.fran.teclas.predict.PlaceInference.maybeRun(this@MainActivity) }
            val changed = predictContext?.contextKey() != snap.contextKey()
            predictContext = snap
            if (rerender || changed) {
                withContext(Dispatchers.Main) {
                    if (::favoritesDockView.isInitialized) renderFavoritesDock()
                    updateSpaceIcon()
                }
            }
        }
    }

    /** Predictor ranking for the current context, or null when not ready (cold start path). */
    private fun predictedPackages(candidates: List<String>, n: Int): List<String>? {
        val snap = predictContext ?: return null
        return runCatching { Predictor.topApps(this, n, candidates, snap) }.getOrNull()
    }

    private fun appUsageCounts(): Map<String, Int> {
        val raw = prefs().getString(APP_USAGE_PREF, "{}") ?: "{}"
        val json = runCatching { JSONObject(raw) }.getOrNull() ?: return emptyMap()
        return buildMap {
            val keys = json.keys()
            while (keys.hasNext()) {
                val key = keys.next()
                put(key, json.optInt(key, 0))
            }
        }
    }

    private fun appLastLaunches(): Map<String, Long> {
        val raw = prefs().getString(APP_LAST_LAUNCH_PREF, "{}") ?: "{}"
        val json = runCatching { JSONObject(raw) }.getOrNull() ?: return emptyMap()
        return buildMap {
            val keys = json.keys()
            while (keys.hasNext()) {
                val key = keys.next()
                put(key, json.optLong(key, 0L))
            }
        }
    }

    private fun filteredApps(): List<AppEntry> {
        if (query.isBlank()) return apps
        return apps.filter { it.label.contains(query, ignoreCase = true) }
    }

    private fun librarySearchResults(): List<AppEntry> {
        val q = query.trim()
        if (q.isBlank()) return emptyList()
        val matches = apps
            .mapNotNull { app -> appSearchRelevance(app, q).takeIf { it > 0 }?.let { app to it } }
        // Typed intent wins: exact/prefix label matches outrank context every time. The active
        // Space prediction score is only a tie-breaker inside the same text-relevance tier.
        val predictScore: Map<String, Float> = predictContext?.let { snap ->
            runCatching {
                Predictor.scores(this, matches.map { it.first.packageName }, snap).toMap()
            }.getOrNull()
        } ?: emptyMap()
        return matches.sortedWith { leftPair, rightPair ->
            val left = leftPair.first
            val right = rightPair.first
            val relevanceCompare = rightPair.second.compareTo(leftPair.second)
            if (relevanceCompare != 0) return@sortedWith relevanceCompare
            val scoreCompare = (predictScore[right.packageName] ?: 0f)
                .compareTo(predictScore[left.packageName] ?: 0f)
            if (scoreCompare != 0) scoreCompare else collator.compare(left.label, right.label)
        }.map { it.first }
    }

    internal fun builtInLauncherApps(): List<LibraryApp> =
        listOf(teclasSettingsLibraryApp(), themePaneHost.themeStudioLibraryApp(), agendaLibraryApp(), musicLibraryApp(), photosLibraryApp())

    private fun builtInLauncherSearchResults(rawQuery: String): List<SearchResult> {
        val q = rawQuery.trim()
        if (q.isBlank()) return emptyList()
        return builtInLauncherApps()
            .mapNotNull { app ->
                val relevance = builtInAppSearchRelevance(app, q)
                if (relevance <= 0) null else app to relevance
            }
            .sortedWith(compareByDescending<Pair<LibraryApp, Int>> { it.second }.thenBy { it.first.name })
            .map { (app, _) ->
                SearchResult(app.name, "Teclas built-in", app.accent, SearchKind.APP, app.target)
            }
    }

    private fun builtInAppSearchRelevance(app: LibraryApp, rawQuery: String): Int {
        val q = rawQuery.lowercase(Locale.US)
        val name = app.name.lowercase(Locale.US)
        val id = app.target.id.lowercase(Locale.US)
        if (app.target.id == AGENDA_TARGET_ID) {
            val aliases = listOf("agenda", "calendar", "events", "up next", "next", "tasks", "todo", "timeline", "today")
            return when {
                name == q || aliases.any { it == q } -> 1100
                name.startsWith(q) || aliases.any { it.startsWith(q) } -> 980
                name.contains(q) || aliases.any { it.contains(q) } -> 760
                id.contains(q) -> 420
                else -> 0
            }
        }
        val aliases = when (app.target.kind) {
            PaneKind.SETTINGS -> if (app.target.id == THEME_STUDIO_TARGET_ID) {
                listOf("theme", "themes", "theme studio", "studio", "wallpaper", "keyboard theme", "brief themes", "weather themes")
            } else {
                listOf("settings", "teclas settings", "preferences", "customize", "launcher settings")
            }
            PaneKind.MUSIC -> listOf("music", "teclas music", "player", "now playing")
            PaneKind.PHOTOS -> listOf("photos", "zeiss", "zeiss optics", "camera roll", "pictures")
            else -> emptyList()
        }
        return when {
            name == q || aliases.any { it == q } -> 1100
            name.startsWith(q) || aliases.any { it.startsWith(q) } -> 980
            name.contains(q) || aliases.any { it.contains(q) } -> 760
            id.contains(q) -> 420
            else -> 0
        }
    }

    private fun appSearchRelevance(app: AppEntry, rawQuery: String): Int {
        val q = rawQuery.lowercase(Locale.US)
        if (q.isBlank()) return 0
        val label = app.label.lowercase(Locale.US)
        val short = app.shortName.lowercase(Locale.US)
        val pkg = app.packageName.lowercase(Locale.US)
        val words = label.split(Regex("\\s+")).filter { it.isNotBlank() }
        return when {
            label == q || short == q -> 1000
            label.startsWith(q) || short.startsWith(q) -> 900
            words.any { it == q } -> 860
            words.any { it.startsWith(q) } -> 820
            label.contains(q) || short.contains(q) -> 700
            pkg.substringAfterLast('.').startsWith(q) -> 260
            pkg.contains(q) -> 120
            else -> 0
        }
    }

    /**
     * The contextual suggestion row for search: only when the active Space was detected
     * from a strong signal (place / driving / bluetooth / headphones, or a manual lock)
     * AND that Space has actually learned launches. Weak or unlearned context -> null,
     * normal ranking untouched.
     */
    internal fun contextSuggestionResults(exclude: Set<String>): Pair<String, List<SearchResult>>? {
        val snap = predictContext ?: return null
        val det = SpaceManager.detect(this, snap)
        if (!det.strong && !det.locked) return null
        val installed = apps.associateBy { it.packageName }
        val learned = runCatching {
            Predictor.spaceTopLearned(this, det.space.id, 6, installed.keys)
        }.getOrDefault(emptyList())
            .filter { it !in exclude && it != packageName }
            .take(3)
        if (learned.isEmpty()) return null
        val label = when {
            snap.driving -> "Because you're driving"
            det.space.id == "fitness" -> "Because you're at the gym"
            det.space.id == "travel" -> "Because you're at the airport"
            det.space.id == "work" -> "Because you're at work"
            det.space.id == "home" -> "Because you're home"
            det.space.id == "commute" -> "For your commute"
            det.space.id == "night" -> "For tonight"
            else -> "In ${det.space.name}"
        }
        return label to learned.mapNotNull { pkg ->
            installed[pkg]?.let {
                SearchResult(it.label, det.space.name, it.brandColor, SearchKind.APP, it.toPaneTarget())
            }
        }
    }

    /**
     * Invalidate the [universalSearchResults] memo. Called when an async source lands or a setting
     * row applies a pref — the two things that change results without changing the query.
     */
    internal fun invalidateSearchResults() { searchGeneration++ }

    private var searchResultsMemo: List<SearchResult>? = null
    private var searchResultsMemoKey = -1

    /**
     * Memoized per (query, generation). The uncached body re-scores every installed app, sorts,
     * classifies the query, and builds 37+ setting entries — and it used to run on EVERY view
     * rebuild, of which there are 6-9 per query. The async sources each bump the generation when
     * they land, so this stays correct while collapsing the repeats within one beat.
     */
    internal fun universalSearchResults(): List<SearchResult> {
        val key = searchGeneration
        searchResultsMemo?.let { if (searchResultsMemoKey == key) return it }
        val out = computeUniversalSearchResults()
        searchResultsMemoKey = key
        searchResultsMemo = out
        return out
    }

    private fun computeUniversalSearchResults(): List<SearchResult> {
        val q = query.trim()
        if (q.isBlank()) return emptyList()
        val results = mutableListOf<SearchResult>()
        librarySearchResults().take(5).forEach { app ->
            results.add(SearchResult(app.label, "Open", app.brandColor, SearchKind.APP, app.toPaneTarget()))
        }
        results.addAll(builtInLauncherSearchResults(q).take(3))
        // Type-to-customize: matching launcher settings surface as tappable results that apply
        // live in place — search is the settings screen.
        results.addAll(settingSearchResults())
        // Playable Spotify tracks for this query (fetched async in scheduleMusicSearch) — tap to play
        // in place, no need to leave the homescreen.
        if (spotifyQuickQuery == q) results.addAll(spotifyQuickResults)
        if (gmailQuickQuery == q) results.addAll(gmailQuickResults)
        if (fileQuickQuery == q) results.addAll(fileQuickResults)
        // Semantic hits ("scan documents" → Drive) — skip anything string matching already found.
        if (semanticQuickQuery == q) {
            val seenTitles = results.map { it.title.lowercase(Locale.US) }.toSet()
            results.addAll(semanticQuickResults.filter { it.title.lowercase(Locale.US) !in seenTitles })
        }
        if (looksLikeTravelQuery(q)) {
            val boarding = q.lowercase(Locale.US).contains("boarding") || q.lowercase(Locale.US).contains("pass")
            results.add(0, SearchResult(
                if (boarding) "Boarding passes" else "Flights & boarding passes",
                "From your Gmail", 0xFF5FD0C4.toInt(), SearchKind.TRAVEL, null
            ) { travelPaneHost.openTravelOverlay(startOnBoardingPasses = boarding) })
        }
        // Recall: "what was I supposed to do with ana?" surfaces stored commitments up top.
        searchCommitmentResults(q).forEachIndexed { i, r -> results.add(minOf(i, results.size), r) }
        results.addAll(searchContactResults(q))
        results.addAll(searchMessageResults(q))
        results.addAll(searchCalendarResults(q))
        // Intent-aware shaping: a recognized command ("play jazz", "timer 5") means the user
        // wants an ACTION — surface the apps that can serve it, drop the web noise.
        val commandIntent = AgenticRouter.classify(q) != null
        if (q.lowercase(Locale.US).startsWith("play ")) {
            apps.filter {
                com.fran.teclas.predict.AppCategories.of(this, it.packageName) == com.fran.teclas.predict.AppCategory.MUSIC
            }.take(3).forEachIndexed { i, app ->
                results.add(minOf(1 + i, results.size), SearchResult(
                    app.label, "Play “${q.removePrefix("play ").removePrefix("Play ").trim()}” here",
                    app.brandColor, SearchKind.APP, app.toPaneTarget()
                ))
            }
        }
        // Google fallback rows — only when NO rich representation exists for this query.
        // A rich card (Brave) or sports card (ESPN) IS the answer; anything else is noise.
        // Exception: a definition card is context, not the destination — a bare word like
        // "serendipity" keeps its web results below the card.
        // A command intent suppresses them entirely: "play jazz" wants music, not links.
        val richCard = searchResultsHost.searchRichAnswer()
        // Definitions and landmarks are "learn more" context — keep the web results below them.
        // Finance/weather/crypto/POI cards ARE the answer, so they suppress the web rows.
        val richIsTheAnswer = richCard != null && richCard.vertical !in setOf("definitions", "landmark")
        // (The landmark ride offer is rendered as a card in Zone 1, directly under the hero —
        // see searchRideOffer()/braveRideCard() — not added to this kind-grouped list.)
        // A nearby-places card IS the answer for local intent — web rows under it are noise.
        if (webFallbackQuery == q && !richIsTheAnswer && searchResultsHost.searchSportsCard() == null &&
            searchPlaces() == null && !commandIntent) {
            results.addAll(webFallbackResults)
        }
        // A typed URL ("theverge.com") is an unambiguous intent — rank opening the site itself
        // first, so GO fires it directly. Tap = in-launcher sheet, long-press = full browser.
        val urlMatch = InAppGoogleSearchEngine.urlFromQuery(q)
        urlMatch?.let { url ->
            val host = Uri.parse(url).host ?: q
            results.add(0, SearchResult(
                "Open $host", "Website · hold for browser", 0xFF4285F4.toInt(), SearchKind.WEB, null,
                action = { openUrlDirectly(url) },
                longAction = { startSafeIntent(Intent(Intent.ACTION_VIEW, Uri.parse(url)), "No browser available") }
            ))
        }
        // A typed phone number is an unambiguous call intent — place the call directly (placeCall
        // → ACTION_CALL), not just open the dialer. Skipped when a real contact already matched
        // (more specific, stays on top) or the query also parsed as a URL (e.g. a bare IP — don't
        // show both).
        if (urlMatch == null) {
            phoneNumberFromQuery(q)?.let { number ->
                val hasRealContactMatch = results.any { it.kind == SearchKind.CONTACT && it.title != "Connect contacts" }
                if (!hasRealContactMatch) {
                    results.add(0, SearchResult(q, "Tap to call", 0xFF5FD0C4.toInt(), SearchKind.CONTACT, null) {
                        placeCall(number)
                    })
                }
            }
        }
        // Ride intent ("take me to X", "go to X", "uber", "ride") → a top-ranked Uber card. Tap/GO
        // opens the Uber app with pickup = the rider's current GPS and the destination preloaded
        // (geocoded to coords in launchUber). Ranked first so GO fires it directly. Guard: if the
        // destination is the name of an installed app ("go to youtube"), yield to the app instead —
        // "go to" is broad, so a real app match wins over the ride reading.
        uberDestinationFromQuery(q)?.let { dest ->
            val matchesApp = dest.isNotBlank() && apps.any { it.label.equals(dest, ignoreCase = true) }
            if (!matchesApp) {
                // Context resolution: "take me to hotel" ties to the hotel in your calendar; "home"/
                // "work"/"airport" tie to your saved places (with coords). Falls back to the raw text.
                val resolved = resolveRideDestination(dest)
                val title = if (resolved == null) "Open Uber" else "Uber to ${resolved.label}"
                val sub = when {
                    resolved == null -> "Ride · pickup at your location"
                    resolved.contextNote != null -> "Ride · your location · ${resolved.contextNote}"
                    else -> "Ride · pickup at your location → destination preloaded"
                }
                results.add(0, SearchResult(title, sub, 0xFF1FBAD6.toInt(), SearchKind.RIDE, null) {
                    if (resolved == null) launchUber("") else launchUberResolved(resolved)
                })
            }
        }
        if (q.length >= 2) {
            val directHits = results.isNotEmpty()
            // Full results page in the in-launcher sheet (Brave when connected) — the old AI-pane
            // text list felt like a popup, not search.
            val web = SearchResult("Search the web", q, 0xFF4285F4.toInt(), SearchKind.WEB, null) { launchInAppGoogleSearch(q) }
            val ai = SearchResult("Ask Teclas AI", q, 0xFF8AB4F8.toInt(), SearchKind.AI, aiTarget(SearchRouter.cleanPrompt(q))) {
                askGemini(SearchRouter.cleanPrompt(q))
            }
            // With no model reachable, an "answer" route has nothing to answer with — it's a web query.
            val verdict = SearchRouter.route(q, directHits)
            val answerable = verdict.route == SearchRouter.Route.ANSWER &&
                GeminiClient.configured(prefs()) && !aiInlineDeclined(q)
            when {
                // The answer is already rendering at the top of the band, so an "Ask AI" row would
                // just be a second way to ask the same question. Offer the web as the escape hatch.
                answerable -> results.add(web.copy(title = "Search the web instead"))
                !directHits -> {
                    results.add(web)
                    results.add(ai.copy(title = "Ask Teclas AI instead"))
                }
                else -> results.add(web.copy(title = "Search web for \"$q\""))
            }
        }
        return results.distinctBy { "${it.kind}:${it.title}:${it.subtitle}" }.take(14)
    }

    internal fun looksLikeAiQuestion(text: String): Boolean {
        val lower = text.lowercase(Locale.US).trim()
        return lower.endsWith("?") ||
            lower.startsWith("ask ") ||
            lower.startsWith("ai ") ||
            lower.startsWith("gemini ") ||
            listOf("what ", "why ", "how ", "when ", "where ", "who ", "summarize ", "explain ", "draft ").any { lower.startsWith(it) }
    }

    // Web-vs-answer routing now lives in SearchRouter (tested, and aware that an offline model must
    // not answer live questions). The old looksLikeWebSearch heuristic was replaced by it.

    private fun looksLikeTravelQuery(text: String): Boolean {
        val lower = text.lowercase(Locale.US)
        return listOf("flight", "flights", "boarding", "boarding pass", "trip", "trips", "travel", "itinerary")
            .any { lower.contains(it) }
    }

    // A typed phone number ("5551234567", "(555) 123-4567", "+1 555 123 4567") — only digits
    // plus phone-shaped separators and at most one leading '+', no letters, a plausible digit
    // count. Returns the dialable tel: value (digits + optional leading +), or null.
    private fun phoneNumberFromQuery(text: String): String? {
        val clean = text.trim()
        if (clean.isEmpty() || clean.any { it.isLetter() }) return null
        if (!clean.all { it.isDigit() || it in " -().+" }) return null
        if (clean.contains('+') && (!clean.startsWith('+') || clean.count { it == '+' } > 1)) return null
        val digits = clean.filter { it.isDigit() }
        if (digits.length !in 7..15) return null
        return (if (clean.startsWith('+')) "+" else "") + digits
    }

    // ── Uber / rides ─────────────────────────────────────────────────────────
    // A ride intent in the query. Returns the destination text ("" for a bare "uber"/"ride" with
    // no destination — just open Uber), or null when it isn't a ride query. Longer prefixes are
    // tested before their shorter forms ("uber to " before "uber ").
    private fun uberDestinationFromQuery(text: String): String? {
        val clean = text.trim()
        val lower = clean.lowercase(Locale.US)
        if (lower == "uber" || lower == "ride") return ""
        val prefixes = listOf(
            "take me to ", "get me a ride to ", "book a ride to ", "order an uber to ",
            "ride to ", "uber to ", "go to ", "uber ", "ride "
        )
        for (p in prefixes) {
            if (lower.startsWith(p)) return clean.substring(p.length).trim()
        }
        return null
    }

    // Open Uber with pickup = the rider's current location and the destination preloaded. Geocodes
    // the destination to coordinates off the main thread (best accuracy); on failure, falls back to
    // passing the raw address as dropoff[formatted_address]. Uses the uber:// scheme when the app is
    // installed (most reliable preload), else the m.uber.com/ul universal link (app or web/install).
    private fun launchUber(destination: String) {
        // Context-resolve first (calendar / saved places), so a shortcut-prompt "hotel" also ties to
        // the calendar, exactly like the search card does. Blank / nothing to go on → open Uber.
        val resolved = resolveRideDestination(destination.trim())
        if (resolved == null) { openUberRide(null, null, null); return }
        launchUberResolved(resolved)
    }

    // A ride destination after context resolution: either exact coords (saved place / geocoded
    // calendar hit) or an address string still to geocode. [label] is what the card shows.
    private data class RideDest(
        val label: String,
        val lat: Double? = null,
        val lng: Double? = null,
        val address: String? = null,
        val contextNote: String? = null
    )

    // Turn the typed destination into a real place using the user's own context, in priority order:
    //   1. Saved places (Home / Work / Gym / Airport, or a named place) — already have coordinates.
    //   2. Calendar — an event whose title/location matches (e.g. "hotel"), or the next event with a
    //      location for generic words ("my meeting", "reservation"). Uses the event's location.
    //   3. Raw text — geocode whatever was typed.
    // Returns null only when there's nothing to go on (blank query, no imminent event) → open Uber.
    private fun resolveRideDestination(raw: String): RideDest? {
        val d = raw.trim()
        matchSavedPlace(d)?.let { p -> return RideDest(p.name, p.lat, p.lng, contextNote = "destination from your saved places") }
        matchCalendarDestination(d)?.let { return it }
        if (d.isBlank()) return null
        return RideDest(d, address = d)
    }

    private fun matchSavedPlace(dest: String): com.fran.teclas.predict.Place? {
        val key = dest.trim().lowercase(Locale.US).removePrefix("the ").trim()
        if (key.isBlank()) return null
        val places = runCatching { com.fran.teclas.predict.PlaceStore.places(this) }.getOrDefault(emptyList())
        if (places.isEmpty()) return null
        val kindWord = mapOf(
            "home" to com.fran.teclas.predict.PlaceKind.HOME,
            "work" to com.fran.teclas.predict.PlaceKind.WORK,
            "office" to com.fran.teclas.predict.PlaceKind.WORK,
            "gym" to com.fran.teclas.predict.PlaceKind.GYM,
            "airport" to com.fran.teclas.predict.PlaceKind.AIRPORT
        )[key]
        if (kindWord != null) places.firstOrNull { it.kind == kindWord }?.let { return it }
        return places.firstOrNull {
            val n = it.name.lowercase(Locale.US)
            n == key || n.contains(key) || key.contains(n)
        }
    }

    private fun matchCalendarDestination(dest: String): RideDest? {
        val events = calendarEvents.filter { it.location.isNotBlank() }
        if (events.isEmpty()) return null
        val now = System.currentTimeMillis()
        val upcoming = events.filter { it.endMs >= now }.sortedBy { it.beginMs }
        val key = dest.trim().lowercase(Locale.US).removePrefix("the ").trim()
        val generic = key.isBlank() || key in setOf(
            "event", "my event", "next event", "meeting", "my meeting", "appointment",
            "my appointment", "reservation", "my reservation", "booking"
        )
        val ev = if (generic) {
            upcoming.firstOrNull()
        } else {
            (upcoming + events).firstOrNull { it.title.contains(key, true) || it.location.contains(key, true) }
        } ?: return null
        val label = ev.location.takeIf { it.length > 3 } ?: ev.title
        return RideDest(label, address = ev.location, contextNote = "destination from your calendar")
    }

    // Fire the ride: exact coords open Uber immediately; an address geocodes off the main thread first.
    private fun launchUberResolved(d: RideDest) {
        if (d.lat != null && d.lng != null) { openUberRide(d.lat, d.lng, d.label); return }
        val addr = (d.address ?: d.label).trim()
        if (addr.isBlank()) { openUberRide(null, null, null); return }
        Toast.makeText(this, "Setting up your ride…", Toast.LENGTH_SHORT).show()
        mediaUiScope.launch(Dispatchers.IO) {
            val hit = runCatching {
                @Suppress("DEPRECATION")
                android.location.Geocoder(this@MainActivity, Locale.getDefault())
                    .getFromLocationName(addr, 1)?.firstOrNull()
            }.getOrNull()
            runOnUiThread { openUberRide(hit?.latitude, hit?.longitude, d.label) }
        }
    }

    internal fun openUberRide(lat: Double?, lng: Double?, nickname: String?) {
        val uberInstalled = runCatching { packageManager.getPackageInfo("com.ubercab", 0); true }.getOrDefault(false)
        val host = if (uberInstalled) "uber://" else "https://m.uber.com/ul/"
        // Pickup: use the app's known location explicitly (which honors the demo-location override,
        // so a Paris demo has a Paris pickup — not the phone's real GPS). Fall back to Uber's
        // "my_location" only when we have no fix at all.
        val here = AgenticLocation.lastKnown(this)
        val pickup = if (here != null)
            "pickup[latitude]=${here.latitude}&pickup[longitude]=${here.longitude}"
        else "pickup=my_location"
        val sb = StringBuilder("${host}?action=setPickup&$pickup")
        if (lat != null && lng != null) {
            sb.append("&dropoff[latitude]=").append(lat)
            sb.append("&dropoff[longitude]=").append(lng)
            if (!nickname.isNullOrBlank()) sb.append("&dropoff[nickname]=").append(Uri.encode(nickname))
        } else if (!nickname.isNullOrBlank()) {
            sb.append("&dropoff[formatted_address]=").append(Uri.encode(nickname))
        }
        val intent = Intent(Intent.ACTION_VIEW, Uri.parse(sb.toString())).addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
        if (uberInstalled) intent.setPackage("com.ubercab")
        startSafeIntent(intent, "Couldn't open Uber")
    }

    // ── Type-to-customize ────────────────────────────────────────────────────
    // Launcher settings exposed as universal-search results. Typing "glass", "accent",
    // "icon pack"… surfaces the matching control as a result card; tapping applies it
    // immediately and the results re-render in place with the new state. Search is the
    // settings screen — the pane stays available for browsing, but is never required.

    private fun settingSearchResults(): List<SearchResult> {
        val q = query.trim().lowercase(Locale.US)
        if (q.length < 3) return emptyList()
        fun score(entry: SettingSearchEntry): Int = entry.keywords.maxOf { kw ->
            when {
                kw == q -> 3
                kw.startsWith(q) -> 2
                q.length >= 4 && kw.contains(q) -> 1
                else -> 0
            }
        }
        return settingSearchEntries()
            .map { it to score(it) }
            .filter { it.second > 0 }
            .sortedByDescending { it.second }
            .take(4)
            .map { (entry, _) ->
                SearchResult(entry.title, entry.state, goKeyColor, SearchKind.SETTING, null) {
                    entry.perform()
                }
            }
    }

