    // Re-render whichever search surface is showing so an applied setting is visible
    // immediately, with the query and keyboard untouched.
    private fun refreshSearchSurfaces() {
        // A setting row just flipped a pref that the result list renders (its own On/Off label,
        // and possibly which rows exist at all).
        invalidateSearchResults()
        if (libraryOpen) refreshLibraryContent()
        if (isWidgetUniversalSearchActive()) searchResultsHost.refreshWidgetSearchContent()
        if (isUnfoldedInnerLayoutActive()) refreshUnfoldedLibraryContent()
    }

    // Theme Studio launch/apply, go-color cycling, and launcher-look (theme mode)
    // wiring live in ThemePaneHost.

    private fun cycleKeyboardTheme() {
        val order = (listOf(
            KEYBOARD_THEME_DEFAULT, KEYBOARD_THEME_TECLAS, KEYBOARD_THEME_SKEUO, KEYBOARD_THEME_GOKEYS,
            KEYBOARD_THEME_HYPER3D, KEYBOARD_THEME_HYPER3D_BLACK, KEYBOARD_THEME_HYPER3D_LIGHT,
            KEYBOARD_THEME_BRUSHED, KEYBOARD_THEME_SEEME
        ) + KeyboardThemeDrawables.cycleThemes)
            .distinct()
            .filter { it != KEYBOARD_THEME_SKEUO || ProManager.isUnlocked(this) }
        keyboardTheme = order[(order.indexOf(keyboardTheme) + 1).mod(order.size)]
        prefs().edit().putString(KEYBOARD_THEME_PREF, keyboardTheme).apply()
        render()
    }

    private fun selectKeyboardTheme(theme: String) {
        if (theme == KEYBOARD_THEME_SKEUO && !ProManager.isUnlocked(this)) {
            showUpgradeSheet(ProFeature.SKEUO_THEME)
            return
        }
        keyboardTheme = theme
        prefs().edit().putString(KEYBOARD_THEME_PREF, theme).apply()
        render()
    }

    private fun keyboardSizeLabel(): String = when {
        keyboardSize >= 75 -> "Large"
        keyboardSize >= 35 -> "Medium"
        else -> "Compact"
    }

    private fun cycleKeyboardSize() {
        val presets = listOf(0, 50, 100)
        keyboardSize = presets.firstOrNull { it > keyboardSize } ?: presets.first()
        prefs().edit().putInt(KEYBOARD_SIZE_PREF, keyboardSize).apply()
        render()
    }

    private fun iconSizeLabel(): String = when {
        appIconSize >= 70 -> "Large"
        appIconSize >= 35 -> "Medium"
        else -> "Default"
    }

    private fun cycleIconSize() {
        val presets = listOf(0, 35, 70)
        appIconSize = presets.firstOrNull { it > appIconSize } ?: presets.first()
        prefs().edit().putInt(APP_ICON_SIZE_PREF, appIconSize).apply()
        renderFavoritesDock()
    }

    // Small/Medium/Large steps for the type-to-customize surface — the settings-pane slider
    // covers the full continuous 0..100 range.
    private fun cycleSearchFontSize() {
        val presets = listOf(15, 50, 85)
        val next = presets.firstOrNull { it > searchFontSizePref() } ?: presets.first()
        prefs().edit().putInt(SEARCH_FONT_SIZE_PREF, next).apply()
    }

